export enum AppMode {
  ANIMAL_BEHAVIOR = 'ANIMAL_BEHAVIOR',
  VET_DERM = 'VET_DERM',
  CROP_DOCTOR = 'CROP_DOCTOR',
}

export interface ModeConfig {
  id: AppMode;
  title: string;
  description: string;
  icon: string;
  acceptedFileTypes: string;
  inputLabel: string;
}

export interface AnalysisResult {
  text: string;
}

import { GoogleGenAI } from "@google/genai";
import { AppMode } from "../types";

// Initialize the client
// NOTE: In a production environment, never expose keys on the client side.
// This is strictly for the competition/demo requirement.
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const MODEL_NAME = "gemini-2.5-flash";

/**
 * Converts a File object to a Base64 string.
 */
const fileToPart = (file: File): Promise<{ inlineData: { data: string; mimeType: string } }> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onloadend = () => {
      if (typeof reader.result === 'string') {
        // Remove the data URL prefix (e.g., "data:image/jpeg;base64,")
        const base64Data = reader.result.split(',')[1];
        resolve({
          inlineData: {
            data: base64Data,
            mimeType: file.type,
          },
        });
      } else {
        reject(new Error("Failed to read file"));
      }
    };
    reader.onerror = reject;
    reader.readAsDataURL(file);
  });
};

/**
 * Analyzes the uploaded media based on the selected mode.
 */
export const analyzeMedia = async (file: File, mode: AppMode): Promise<string> => {
  try {
    const mediaPart = await fileToPart(file);

    let systemInstructionText = "You are Kisan-Rakshak AI, an expert agricultural and veterinary assistant. ";

    // Tailor instruction slightly per mode, though the core requirement is the same
    switch (mode) {
      case AppMode.ANIMAL_BEHAVIOR:
        systemInstructionText += "Your specialty is analyzing animal movements and behavior from video/images to detect distress, illness, or abnormalities.";
        break;
      case AppMode.VET_DERM:
        systemInstructionText += "Your specialty is veterinary dermatology. Analyze skin lesions, rashes, or parasites on animals.";
        break;
      case AppMode.CROP_DOCTOR:
        systemInstructionText += "Your specialty is plant pathology. Analyze crop leaves for diseases, pests, or nutrient deficiencies.";
        break;
    }

    systemInstructionText += `
      \n\nCRITICAL OUTPUT RULES:
      1. Analyze the input media.
      2. Identify the disease, stress sign, or behavioral issue.
      3. Provide the Diagnosis, Severity, and Immediate First-Aid/Remedies.
      4. LANGUAGE: Provide the ENTIRE output in MARATHI language first.
      5. Follow the Marathi response immediately with an ENGLISH translation.
      6. Use bold headers for "Diagnosis", "Severity", and "Remedies".
    `;

    const response = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: {
        parts: [mediaPart, { text: "Analyze this media according to your system instructions." }]
      },
      config: {
        systemInstruction: systemInstructionText,
        // Optional: reduce thinking budget for faster response if needed, 
        // but default is fine for quality.
        temperature: 0.4, // Keep it factual
      }
    });

    return response.text || "No response generated.";
  } catch (error) {
    console.error("Gemini API Error:", error);
    throw new Error("Failed to analyze media. Please try again.");
  }
};

