import React, { useState } from 'react';

interface FileUploadProps {
  label: string;
  acceptedTypes: string;
  onFileSelect: (file: File) => void;
}

export const FileUpload: React.FC<FileUploadProps> = ({ label, acceptedTypes, onFileSelect }) => {
  const [dragActive, setDragActive] = useState(false);
  const [fileName, setFileName] = useState<string | null>(null);

  const handleDrag = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    if (e.type === "dragenter" || e.type === "dragover") {
      setDragActive(true);
    } else if (e.type === "dragleave") {
      setDragActive(false);
    }
  };

  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setDragActive(false);
    if (e.dataTransfer.files && e.dataTransfer.files[0]) {
      handleFile(e.dataTransfer.files[0]);
    }
  };

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    e.preventDefault();
    if (e.target.files && e.target.files[0]) {
      handleFile(e.target.files[0]);
    }
  };

  const handleFile = (file: File) => {
    setFileName(file.name);
    onFileSelect(file);
  };

  return (
    <div className="w-full">
      <div
        className={`relative flex flex-col items-center justify-center w-full h-64 border-2 border-dashed rounded-2xl transition-colors duration-300 ${
          dragActive
            ? "border-green-600 bg-green-50"
            : "border-gray-300 bg-white hover:border-green-400 hover:bg-green-50/30"
        }`}
        onDragEnter={handleDrag}
        onDragLeave={handleDrag}
        onDragOver={handleDrag}
        onDrop={handleDrop}
      >
        <div className="flex flex-col items-center justify-center pt-5 pb-6 text-center px-4">
          <svg
            className={`w-12 h-12 mb-4 ${dragActive ? 'text-green-600' : 'text-gray-400'}`}
            aria-hidden="true"
            xmlns="http://www.w3.org/2000/svg"
            fill="none"
            viewBox="0 0 20 16"
          >
            <path
              stroke="currentColor"
              strokeLinecap="round"
              strokeLinejoin="round"
              strokeWidth="2"
              d="M13 13h3a3 3 0 0 0 0-6h-.025A5.56 5.56 0 0 0 16 6.5 5.5 5.5 0 0 0 5.207 5.021C5.137 5.017 5.071 5 5 5a4 4 0 0 0 0 8h2.167M10 15V6m0 0L8 8m2-2 2 2"
            />
          </svg>
          <p className="mb-2 text-sm text-gray-500">
            <span className="font-semibold text-green-700">Click to upload</span> or drag and drop
          </p>
          <p className="text-xs text-gray-400 mt-1">{label}</p>
          {fileName && (
             <div className="mt-4 px-3 py-1 bg-green-100 text-green-800 rounded-full text-xs font-medium">
               Selected: {fileName}
             </div>
          )}
        </div>
        <input
          id="dropzone-file"
          type="file"
          className="absolute w-full h-full opacity-0 cursor-pointer"
          accept={acceptedTypes}
          onChange={handleChange}
        />
      </div>
    </div>
  );
};

import React, { useState, useCallback } from 'react';
import { AppMode, ModeConfig } from './types';
import { ModeCard } from './components/ModeCard';
import { FileUpload } from './components/FileUpload';
import { Spinner } from './components/Spinner';
import { analyzeMedia } from './services/geminiService';

// Configuration for the 3 modes
const MODES: ModeConfig[] = [
  {
    id: AppMode.ANIMAL_BEHAVIOR,
    title: 'Animal Behavior Detector',
    description: 'Upload a video or GIF of your livestock. AI detects stress, lameness, or abnormal behavior patterns.',
    icon: '🐄',
    acceptedFileTypes: 'video/*,image/gif',
    inputLabel: 'Upload Video (MP4, WEBM) or GIF (Max 10MB)',
  },
  {
    id: AppMode.VET_DERM,
    title: 'Veterinary Derm-Scan',
    description: 'Upload a clear photo of skin issues, rashes, or lumps. AI identifies potential dermatological diseases.',
    icon: '🐕',
    acceptedFileTypes: 'image/*',
    inputLabel: 'Upload Image (JPG, PNG)',
  },
  {
    id: AppMode.CROP_DOCTOR,
    title: 'Agri-Vision Crop Doctor',
    description: 'Upload a close-up photo of a crop leaf. AI diagnoses diseases, pest damage, or nutrient deficiency.',
    icon: '🌱',
    acceptedFileTypes: 'image/*',
    inputLabel: 'Upload Leaf Image (JPG, PNG)',
  },
];

const App: React.FC = () => {
  const [activeMode, setActiveMode] = useState<ModeConfig | null>(null);
  const [file, setFile] = useState<File | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [result, setResult] = useState<string | null>(null);
  const [error, setError] = useState<string | null>(null);

  const handleModeSelect = (mode: ModeConfig) => {
    setActiveMode(mode);
    resetState();
  };

  const handleBack = () => {
    setActiveMode(null);
    resetState();
  };

  const resetState = () => {
    setFile(null);
    setResult(null);
    setError(null);
    setIsLoading(false);
  };

  const handleFileSelect = useCallback((selectedFile: File) => {
    if (selectedFile.size > 20 * 1024 * 1024) { // 20MB Check
        setError("File is too large. Please upload a file smaller than 20MB.");
        return;
    }
    setFile(selectedFile);
    setError(null);
  }, []);

  const handleAnalyze = async () => {
    if (!file || !activeMode) return;

    setIsLoading(true);
    setError(null);
    setResult(null);

    try {
      const analysisText = await analyzeMedia(file, activeMode.id);
      setResult(analysisText);
    } catch (err: any) {
      setError(err.message || "An unexpected error occurred.");
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-green-50 to-emerald-100 flex flex-col font-sans">
      {/* Header */}
      <header className="bg-white/80 backdrop-blur-md shadow-sm sticky top-0 z-10">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 h-16 flex items-center justify-between">
          <div className="flex items-center space-x-2" onClick={handleBack} role="button">
            <span className="text-3xl">🚜</span>
            <h1 className="text-2xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-green-700 to-emerald-600">
              Kisan-Rakshak AI
            </h1>
          </div>
          {activeMode && (
            <button
              onClick={handleBack}
              className="text-sm text-green-700 hover:text-green-900 font-medium px-3 py-1 rounded-md hover:bg-green-50 transition-colors"
            >
              ← Back to Home
            </button>
          )}
        </div>
      </header>

      {/* Main Content */}
      <main className="flex-grow flex flex-col items-center justify-start p-4 md:p-8 max-w-7xl mx-auto w-full">

        {/* LANDING PAGE - MODE SELECTION */}
        {!activeMode && (
          <div className="w-full max-w-5xl animate-fade-in-up">
            <div className="text-center mb-12">
              <h2 className="text-4xl md:text-5xl font-extrabold text-gray-900 mb-4 tracking-tight">
                AI Diagnostics for <span className="text-green-600">Smarter Farming</span>
              </h2>
              <p className="text-lg text-gray-600 max-w-2xl mx-auto">
                Select a diagnostic tool below to identify crop diseases, animal health issues, and more instantly using advanced Artificial Intelligence.
              </p>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-3 gap-6 lg:gap-8">
              {MODES.map((mode) => (
                <ModeCard key={mode.id} mode={mode} onClick={handleModeSelect} />
              ))}
            </div>
          </div>
        )}

        {/* ACTIVE MODE - UPLOAD & RESULTS */}
        {activeMode && (
          <div className="w-full max-w-3xl bg-white rounded-3xl shadow-xl overflow-hidden border border-green-100 flex flex-col">

            {/* Active Mode Header */}
            <div className="bg-green-600 p-6 md:p-8 text-white">
              <div className="flex items-center space-x-4">
                <span className="text-4xl bg-white/20 p-2 rounded-xl backdrop-blur-sm">{activeMode.icon}</span>
                <div>
                  <h2 className="text-2xl font-bold">{activeMode.title}</h2>
                  <p className="text-green-100 opacity-90 text-sm mt-1">{activeMode.description}</p>
                </div>
              </div>
            </div>

            <div className="p-6 md:p-8 space-y-8">

              {/* Upload Section */}
              {!result && !isLoading && (
                <div className="space-y-6">
                  <FileUpload 
                    label={activeMode.inputLabel}
                    acceptedTypes={activeMode.acceptedFileTypes}
                    onFileSelect={handleFileSelect}
                  />

                  {file && (
                    <button
                      onClick={handleAnalyze}
                      className="w-full py-4 bg-gradient-to-r from-green-600 to-emerald-600 text-white rounded-xl font-bold text-lg shadow-lg hover:shadow-green-500/30 hover:scale-[1.01] transition-all duration-200 active:scale-95"
                    >
                      Analyze Now
                    </button>
                  )}

                  {error && (
                    <div className="p-4 bg-red-50 text-red-700 rounded-xl border border-red-200 text-center">
                      ⚠️ {error}
                    </div>
                  )}
                </div>
              )}

              {/* Loading State */}
              {isLoading && <Spinner />}

              {/* Result Section */}
              {result && (
                <div className="animate-fade-in space-y-6">
                  <div className="flex items-center justify-between border-b pb-4">
                    <h3 className="text-xl font-bold text-gray-800">Diagnostic Report</h3>
                    <button 
                      onClick={resetState}
                      className="text-sm text-green-600 font-medium hover:underline"
                    >
                      Analyze Another
                    </button>
                  </div>

                  <div className="prose prose-green max-w-none bg-green-50/50 p-6 rounded-2xl border border-green-100">
                     <div className="whitespace-pre-wrap text-gray-800 leading-relaxed font-medium">
                       {result}
                     </div>
                  </div>

                  <div className="flex justify-center pt-4">
                    <p className="text-xs text-gray-400">
                      Disclaimer: AI generated advice. Always consult a certified veterinarian or agricultural expert for confirmation.
                    </p>
                  </div>
                </div>
              )}
            </div>
          </div>
        )}
      </main>
    </div>
  );
};

export default App;

