import { GoogleGenAI, Modality } from "@google/genai";
import { AppMode } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

/**
 * Helper to convert Blob/File to Base64
 */
const blobToBase64 = (blob: Blob): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onloadend = () => {
      if (typeof reader.result === 'string') {
        const base64Data = reader.result.split(',')[1];
        resolve(base64Data);
      } else {
        reject(new Error("Failed to read blob"));
      }
    };
    reader.onerror = reject;
    reader.readAsDataURL(blob);
  });
};

/**
 * 1. FAST RESPONSE: Daily Tip using gemini-2.5-flash-lite
 */
export const getDailyTip = async (): Promise<string> => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-lite-latest",
      contents: "Provide a very short, one-sentence practical farming tip for today in Marathi and English.",
    });
    return response.text || "Keep your fields clean and monitor water levels.";
  } catch (e) {
    console.warn("Flash Lite Tip Error", e);
    return "Farm with care today!";
  }
};

/**
 * 2. DIAGNOSTICS: Image/Video Analysis using gemini-3-pro-preview with THINKING
 */
export const analyzeDiagnosticMedia = async (file: File, mode: AppMode): Promise<string> => {
  const base64Data = await blobToBase64(file);
  const mimeType = file.type;

  let systemInstructionText = "You are Kisan-Rakshak AI. ";
  switch (mode) {
    case AppMode.ANIMAL_BEHAVIOR:
      systemInstructionText += "Analyze animal behavior/kinematics for stress/pain.";
      break;
    case AppMode.VET_DERM:
      systemInstructionText += "Analyze skin/dermatological issues in animals.";
      break;
    case AppMode.CROP_DOCTOR:
      systemInstructionText += "Analyze plant pathology (leaves/fruits).";
      break;
  }

  systemInstructionText += `
    \nOUTPUT FORMAT (Marathi & English):
    Diagnosis (निदान): ...
    Severity: ...
    Immediate Action (उपाय): ...
  `;

  // Use Gemini 3 Pro with Thinking for complex diagnosis
  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview",
    contents: {
      parts: [
        { inlineData: { data: base64Data, mimeType } },
        { text: "Analyze this strictly according to medical/agricultural protocols." }
      ]
    },
    config: {
      systemInstruction: systemInstructionText,
      thinkingConfig: { thinkingBudget: 32768 } // High thinking budget for accuracy
    }
  });

  return response.text || "Could not analyze.";
};

/**
 * 3. SEARCH: Market Insights using gemini-2.5-flash with Google Search
 */
export const getMarketInsights = async (query: string): Promise<{text: string, urls: any[]}> => {
  const response = await ai.models.generateContent({
    model: "gemini-2.5-flash-latest",
    contents: `Find current market prices and news for: ${query}. Summarize in Marathi and English.`,
    config: {
      tools: [{ googleSearch: {} }]
    }
  });

  const urls = response.candidates?.[0]?.groundingMetadata?.groundingChunks
    ?.map((c: any) => c.web ? { title: c.web.title, uri: c.web.uri } : null)
    .filter(Boolean) || [];

  return { text: response.text || "No info found.", urls };
};

/**
 * 4. TTS: Generate Speech from Text using gemini-2.5-flash-preview-tts
 */
export const generateSpeech = async (text: string): Promise<string | null> => {
  // Strip special chars for TTS prompt to avoid confusion, keep it short
  const cleanText = text.substring(0, 400) + "..."; 

  const response = await ai.models.generateContent({
    model: "gemini-2.5-flash-preview-tts",
    contents: { parts: [{ text: cleanText }] },
    config: {
      responseModalities: [Modality.AUDIO],
      speechConfig: {
        voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Kore' } },
      },
    },
  });

  const audioPart = response.candidates?.[0]?.content?.parts?.[0];
  if (audioPart && audioPart.inlineData) {
    return audioPart.inlineData.data; // Base64 audio
  }
  return null;
};

/**
 * 5. TRANSCRIPTION: Audio to Text using gemini-2.5-flash
 */
export const transcribeAudio = async (audioBlob: Blob): Promise<string> => {
  const base64Data = await blobToBase64(audioBlob);

  const response = await ai.models.generateContent({
    model: "gemini-2.5-flash-latest",
    contents: {
      parts: [
        { inlineData: { data: base64Data, mimeType: 'audio/wav' } }, // Assuming wav from MediaRecorder
        { text: "Transcribe this audio verbatim. If it is in Marathi, translate to English as well." }
      ]
    }
  });

  return response.text || "";
};

/**
 * 6. CHATBOT: General Assistant using gemini-3-pro-preview
 */
export const chatWithAI = async (history: any[], message: string): Promise<string> => {
  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview",
    contents: [...history, { role: 'user', parts: [{ text: message }] }],
    config: {
      systemInstruction: "You are an expert Indian agricultural assistant. Answer helpfully in Marathi and English."
    }
  });
  return response.text || "I am listening...";
};

import React, { useState, useRef } from 'react';

interface AudioRecorderProps {
  onRecordingComplete: (blob: Blob) => void;
  isProcessing: boolean;
}

export const AudioRecorder: React.FC<AudioRecorderProps> = ({ onRecordingComplete, isProcessing }) => {
  const [isRecording, setIsRecording] = useState(false);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const chunksRef = useRef<Blob[]>([]);

  const startRecording = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      mediaRecorderRef.current = new MediaRecorder(stream);
      chunksRef.current = [];

      mediaRecorderRef.current.ondataavailable = (e) => {
        if (e.data.size > 0) chunksRef.current.push(e.data);
      };

      mediaRecorderRef.current.onstop = () => {
        const blob = new Blob(chunksRef.current, { type: 'audio/wav' });
        onRecordingComplete(blob);
        stream.getTracks().forEach(track => track.stop());
      };

      mediaRecorderRef.current.start();
      setIsRecording(true);
    } catch (err) {
      console.error("Mic error:", err);
      alert("Microphone access denied.");
    }
  };

  const stopRecording = () => {
    if (mediaRecorderRef.current && isRecording) {
      mediaRecorderRef.current.stop();
      setIsRecording(false);
    }
  };

  return (
    <button
      onClick={isRecording ? stopRecording : startRecording}
      disabled={isProcessing}
      className={`p-3 rounded-full transition-all duration-300 ${
        isRecording 
          ? 'bg-red-500 hover:bg-red-600 animate-pulse ring-4 ring-red-200' 
          : 'bg-green-100 text-green-700 hover:bg-green-200'
      } disabled:opacity-50`}
      title={isRecording ? "Stop Recording" : "Start Voice Input"}
    >
      {isRecording ? (
        <svg className="w-6 h-6 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor">
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 10a1 1 0 011-1h4a1 1 0 011 1v4a1 1 0 01-1 1h-4a1 1 0 01-1-1v-4z" />
        </svg>
      ) : (
        <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z" />
        </svg>
      )}
    </button>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import { ChatMessage } from '../types';
import { chatWithAI, transcribeAudio } from '../services/geminiService';
import { AudioRecorder } from './AudioRecorder';

interface ChatInterfaceProps {
  isOpen: boolean;
  onClose: () => void;
}

export const ChatInterface: React.FC<ChatInterfaceProps> = ({ isOpen, onClose }) => {
  const [messages, setMessages] = useState<ChatMessage[]>([
    { role: 'model', text: 'Namaste! I am Kisan-Rakshak Assistant. Ask me anything about your farm.' }
  ]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, isOpen]);

  const handleSend = async () => {
    if (!input.trim() || isLoading) return;

    const userMsg: ChatMessage = { role: 'user', text: input };
    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsLoading(true);

    try {
      const history = messages.map(m => ({ role: m.role, parts: [{ text: m.text }] }));
      const responseText = await chatWithAI(history, input);
      setMessages(prev => [...prev, { role: 'model', text: responseText }]);
    } catch (e) {
      setMessages(prev => [...prev, { role: 'model', text: 'Sorry, I encountered an error. Please try again.' }]);
    } finally {
      setIsLoading(false);
    }
  };

  const handleAudioInput = async (blob: Blob) => {
    setIsLoading(true);
    try {
      // 1. Transcribe
      const text = await transcribeAudio(blob);
      if (text) {
        // 2. Add to chat as user message
        const userMsg: ChatMessage = { role: 'user', text: text, isAudio: true };
        setMessages(prev => [...prev, userMsg]);

        // 3. Get AI response
        const history = messages.map(m => ({ role: m.role, parts: [{ text: m.text }] }));
        const responseText = await chatWithAI(history, text);
        setMessages(prev => [...prev, { role: 'model', text: responseText }]);
      }
    } catch (e) {
      console.error(e);
      setMessages(prev => [...prev, { role: 'model', text: 'Could not hear you properly. Please type.' }]);
    } finally {
      setIsLoading(false);
    }
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-50 bg-black/50 backdrop-blur-sm flex items-end sm:items-center justify-center p-0 sm:p-4">
      <div className="bg-white w-full h-[90vh] sm:h-[600px] sm:max-w-md rounded-t-2xl sm:rounded-2xl flex flex-col shadow-2xl overflow-hidden animate-slide-up">
        {/* Header */}
        <div className="bg-green-600 p-4 flex justify-between items-center text-white shrink-0">
          <div className="flex items-center space-x-2">
            <span className="text-2xl">🤖</span>
            <div>
              <h3 className="font-bold">Kisan Sahayak</h3>
              <p className="text-xs text-green-100">Powered by Gemini 3 Pro</p>
            </div>
          </div>
          <button onClick={onClose} className="p-2 hover:bg-white/10 rounded-full">
            <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
            </svg>
          </button>
        </div>

        {/* Messages */}
        <div ref={scrollRef} className="flex-1 overflow-y-auto p-4 space-y-4 bg-gray-50">
          {messages.map((msg, idx) => (
            <div key={idx} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
              <div className={`max-w-[85%] rounded-2xl p-3 text-sm leading-relaxed shadow-sm ${
                msg.role === 'user' 
                  ? 'bg-green-600 text-white rounded-br-none' 
                  : 'bg-white text-gray-800 border border-gray-200 rounded-bl-none'
              }`}>
                {msg.isAudio && <span className="block text-xs opacity-75 mb-1">🎤 Voice Input</span>}
                {msg.text}
              </div>
            </div>
          ))}
          {isLoading && (
            <div className="flex justify-start">
              <div className="bg-white p-3 rounded-2xl rounded-bl-none border border-gray-200 flex space-x-1">
                <div className="w-2 h-2 bg-green-500 rounded-full animate-bounce"></div>
                <div className="w-2 h-2 bg-green-500 rounded-full animate-bounce delay-100"></div>
                <div className="w-2 h-2 bg-green-500 rounded-full animate-bounce delay-200"></div>
              </div>
            </div>
          )}
        </div>

        {/* Input */}
        <div className="p-3 bg-white border-t border-gray-200 flex items-center space-x-2 shrink-0">
          <AudioRecorder onRecordingComplete={handleAudioInput} isProcessing={isLoading} />
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyPress={(e) => e.key === 'Enter' && handleSend()}
            placeholder="Ask anything..."
            className="flex-1 bg-gray-100 rounded-full px-4 py-3 text-sm focus:outline-none focus:ring-2 focus:ring-green-500"
            disabled={isLoading}
          />
          <button 
            onClick={handleSend}
            disabled={!input.trim() || isLoading}
            className="p-3 bg-green-600 text-white rounded-full hover:bg-green-700 disabled:opacity-50 transition-colors"
          >
            <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 19l9 2-9-18-9 18 9-2zm0 0v-8" />
            </svg>
          </button>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useCallback } from 'react';
import { AppMode, ModeConfig } from './types';
import { ModeCard } from './components/ModeCard';
import { FileUpload } from './components/FileUpload';
import { Spinner } from './components/Spinner';
import { ChatInterface } from './components/ChatInterface';
import { 
  analyzeDiagnosticMedia, 
  getDailyTip, 
  generateSpeech,
  getMarketInsights 
} from './services/geminiService';

const MODES: ModeConfig[] = [
  {
    id: AppMode.ANIMAL_BEHAVIOR,
    title: 'Animal Behavior',
    description: 'Video/GIF analysis for stress & pain detection.',
    icon: '🐄',
    acceptedFileTypes: 'video/*,image/gif',
    inputLabel: 'Video/GIF',
  },
  {
    id: AppMode.VET_DERM,
    title: 'Vet Derm-Scan',
    description: 'Skin lesion & rash identification.',
    icon: '🐕',
    acceptedFileTypes: 'image/*',
    inputLabel: 'Photo',
  },
  {
    id: AppMode.CROP_DOCTOR,
    title: 'Crop Doctor',
    description: 'Leaf disease & pest diagnosis.',
    icon: '🌱',
    acceptedFileTypes: 'image/*',
    inputLabel: 'Leaf Photo',
  },
  {
    id: AppMode.MARKET_INSIGHTS,
    title: 'Market Insights',
    description: 'Real-time prices via Google Search.',
    icon: '📈',
    inputLabel: '', // Not used
    acceptedFileTypes: '' // Not used
  }
];

const App: React.FC = () => {
  const [activeMode, setActiveMode] = useState<ModeConfig | null>(null);
  const [file, setFile] = useState<File | null>(null);
  const [searchQuery, setSearchQuery] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [result, setResult] = useState<string | null>(null);
  const [groundingUrls, setGroundingUrls] = useState<any[]>([]);
  const [error, setError] = useState<string | null>(null);
  const [dailyTip, setDailyTip] = useState<string>('Loading daily tip...');
  const [showChat, setShowChat] = useState(false);
  const [audioUrl, setAudioUrl] = useState<string | null>(null);

  // Load daily tip on mount
  useEffect(() => {
    getDailyTip().then(setDailyTip);
  }, []);

  const handleModeSelect = (mode: ModeConfig) => {
    setActiveMode(mode);
    resetState();
  };

  const handleBack = () => {
    setActiveMode(null);
    resetState();
  };

  const resetState = () => {
    setFile(null);
    setSearchQuery('');
    setResult(null);
    setGroundingUrls([]);
    setError(null);
    setIsLoading(false);
    setAudioUrl(null);
  };

  const handleFileSelect = useCallback((selectedFile: File) => {
    if (selectedFile.size > 20 * 1024 * 1024) {
        setError("File too large (>20MB).");
        return;
    }
    setFile(selectedFile);
    setError(null);
  }, []);

  const playTTS = async () => {
    if (!result || audioUrl) return; // Play existing if there
    setIsLoading(true); // Small loading indicator for audio
    try {
      const audioBase64 = await generateSpeech(result);
      if (audioBase64) {
        const url = `data:audio/mp3;base64,${audioBase64}`;
        setAudioUrl(url);
        new Audio(url).play();
      }
    } catch (e) {
      console.error(e);
    } finally {
      setIsLoading(false);
    }
  };

  const handleAnalyze = async () => {
    if (!activeMode) return;
    setIsLoading(true);
    setError(null);
    setResult(null);
    setAudioUrl(null);

    try {
      if (activeMode.id === AppMode.MARKET_INSIGHTS) {
        if (!searchQuery.trim()) throw new Error("Please enter a crop or market name.");
        const data = await getMarketInsights(searchQuery);
        setResult(data.text);
        setGroundingUrls(data.urls);
      } else {
        if (!file) throw new Error("Please upload a file.");
        const text = await analyzeDiagnosticMedia(file, activeMode.id);
        setResult(text);
      }
    } catch (err: any) {
      setError(err.message || "Error occurred.");
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col font-sans pb-20 sm:pb-0">

      {/* Mobile Sticky Header */}
      <header className="bg-white/95 backdrop-blur-sm sticky top-0 z-20 border-b border-gray-100">
        <div className="max-w-7xl mx-auto px-4 h-14 flex items-center justify-between">
          <div className="flex items-center space-x-2" onClick={handleBack}>
            <span className="text-2xl">🚜</span>
            <h1 className="text-lg font-bold text-green-800">Kisan-Rakshak</h1>
          </div>
          {activeMode && (
            <button onClick={handleBack} className="p-2 text-gray-500 hover:text-green-600">
              <span className="sr-only">Back</span>
              <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
              </svg>
            </button>
          )}
        </div>
      </header>

      <main className="flex-grow p-4 max-w-lg mx-auto w-full sm:max-w-4xl">

        {/* HOME SCREEN */}
        {!activeMode && (
          <div className="space-y-6 animate-fade-in">
            {/* Daily Tip Card */}
            <div className="bg-gradient-to-r from-amber-100 to-orange-50 p-4 rounded-2xl border border-amber-200 shadow-sm">
              <div className="flex items-center space-x-2 mb-2">
                <span className="text-xl">⚡</span>
                <h3 className="text-xs font-bold uppercase tracking-wider text-amber-800">Daily Fast Tip</h3>
              </div>
              <p className="text-sm text-gray-800 font-medium italic">"{dailyTip}"</p>
            </div>

            <div className="space-y-2">
              <h2 className="text-xl font-bold text-gray-900">Diagnostics</h2>
              <div className="grid grid-cols-2 sm:grid-cols-3 gap-3">
                {MODES.filter(m => m.id !== AppMode.MARKET_INSIGHTS).map((mode) => (
                  <ModeCard key={mode.id} mode={mode} onClick={handleModeSelect} />
                ))}
              </div>
            </div>

             <div className="space-y-2">
              <h2 className="text-xl font-bold text-gray-900">Tools</h2>
              <div className="grid grid-cols-1 gap-3">
                 <ModeCard 
                    mode={MODES.find(m => m.id === AppMode.MARKET_INSIGHTS)!} 
                    onClick={handleModeSelect} 
                 />
              </div>
            </div>
          </div>
        )}

        {/* ACTIVE MODE SCREEN */}
        {activeMode && (
          <div className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden min-h-[50vh]">
            <div className="bg-green-50 p-4 border-b border-green-100">
               <h2 className="text-xl font-bold text-green-900 flex items-center gap-2">
                 <span>{activeMode.icon}</span> {activeMode.title}
               </h2>
            </div>

            <div className="p-4 space-y-6">

              {/* Input Section */}
              {!result && !isLoading && (
                <div className="space-y-4">
                  {activeMode.id === AppMode.MARKET_INSIGHTS ? (
                    <div>
                      <label className="block text-sm font-medium text-gray-700 mb-2">Search Market/Crop</label>
                      <input 
                        type="text" 
                        value={searchQuery}
                        onChange={(e) => setSearchQuery(e.target.value)}
                        placeholder="e.g., Onion price in Nashik, Wheat diseases"
                        className="w-full p-3 border border-gray-300 rounded-xl focus:ring-2 focus:ring-green-500 outline-none"
                      />
                    </div>
                  ) : (
                    <FileUpload 
                      label={activeMode.inputLabel || "Upload"} 
                      acceptedTypes={activeMode.acceptedFileTypes || "*"}
                      onFileSelect={handleFileSelect}
                    />
                  )}

                  <button
                    onClick={handleAnalyze}
                    disabled={!file && !searchQuery}
                    className="w-full py-3.5 bg-green-600 text-white rounded-xl font-bold shadow-md active:scale-95 transition-transform disabled:opacity-50 disabled:active:scale-100"
                  >
                    {activeMode.id === AppMode.MARKET_INSIGHTS ? "Search Info" : "Analyze Media"}
                  </button>

                  {error && (
                    <div className="p-3 bg-red-50 text-red-700 rounded-xl text-sm text-center border border-red-100">
                      {error}
                    </div>
                  )}
                </div>
              )}

              {/* Loading */}
              {isLoading && <Spinner />}

              {/* Result */}
              {result && (
                <div className="animate-fade-in space-y-4">
                  {/* TTS Button */}
                  <div className="flex justify-end">
                    <button 
                      onClick={playTTS}
                      className="flex items-center space-x-2 text-sm text-green-700 bg-green-50 px-3 py-1.5 rounded-full hover:bg-green-100"
                    >
                      <span>{audioUrl ? "🔊 Play Again" : "🔈 Read Aloud"}</span>
                    </button>
                    {audioUrl && (
                        <audio src={audioUrl} controls className="hidden" />
                    )}
                  </div>

                  <div className="prose prose-sm prose-green max-w-none bg-gray-50 p-4 rounded-xl border border-gray-100">
                    <div className="whitespace-pre-wrap">{result}</div>
                  </div>

                  {groundingUrls.length > 0 && (
                    <div className="space-y-2">
                       <h4 className="text-xs font-bold uppercase text-gray-500">Sources</h4>
                       <ul className="text-xs space-y-1">
                         {groundingUrls.map((url, i) => (
                           <li key={i}>
                             <a href={url.uri} target="_blank" rel="noreferrer" className="text-blue-600 truncate block">
                               {url.title || url.uri}
                             </a>
                           </li>
                         ))}
                       </ul>
                    </div>
                  )}

                  <button 
                    onClick={resetState}
                    className="w-full py-3 border border-gray-200 text-gray-600 font-medium rounded-xl hover:bg-gray-50"
                  >
                    Start New Analysis
                  </button>
                </div>
              )}
            </div>
          </div>
        )}
      </main>

      {/* Floating Action Button for Chat */}
      <div className="fixed bottom-6 right-6 z-40">
        <button
          onClick={() => setShowChat(true)}
          className="bg-green-600 text-white p-4 rounded-full shadow-lg hover:bg-green-700 transition-all hover:scale-105 active:scale-95 flex items-center justify-center"
          title="Open AI Assistant"
        >
          <span className="text-2xl">💬</span>
        </button>
      </div>

      {/* Chat Overlay */}
      <ChatInterface isOpen={showChat} onClose={() => setShowChat(false)} />

    </div>
  );
};

export default App;

