  id: AppMode;
  title: string;
  description: string;
  icon: string;
  acceptedFileTypes?: string;
  inputLabel?: string;
}

export interface ChatMessage {
  role: 'user' | 'model';
  text: string;
  isAudio?: boolean;
}

export interface AnalysisResult {
  text: string;
  audioData?: string; // Base64 audio for TTS
  groundingUrls?: Array<{title: string, uri: string}>;
}

