import React, { useState, useRef, useEffect } from 'react';
import { ChatMessage } from '../types';
import { chatWithAI, transcribeAudio } from '../services/geminiService';
import { AudioRecorder } from './AudioRecorder';

interface ChatInterfaceProps {
  isOpen: boolean;
  onClose: () => void;
}

export const ChatInterface: React.FC<ChatInterfaceProps> = ({ isOpen, onClose }) => {
  const [messages, setMessages] = useState<ChatMessage[]>([
    { role: 'model', text: 'Namaste! I am Kisan-Rakshak Assistant. Ask me anything about your farm.' }
  ]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [isTranscribing, setIsTranscribing] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, isOpen]);

  const handleSend = async (textToSend?: string) => {
    const text = textToSend || input;
    if (!text.trim() || isLoading) return;

    const userMsg: ChatMessage = { role: 'user', text: text };
    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsLoading(true);

    try {
      const history = messages.map(m => ({ role: m.role, parts: [{ text: m.text }] }));
      const responseText = await chatWithAI(history, text);
      setMessages(prev => [...prev, { role: 'model', text: responseText }]);
    } catch (e) {
      setMessages(prev => [...prev, { role: 'model', text: 'Sorry, I encountered an error. Please try again.' }]);
    } finally {
      setIsLoading(false);
    }
  };

  const handleAudioTranscription = async (blob: Blob) => {
    setIsTranscribing(true);
    setIsLoading(true);
    try {
      // 1. Transcribe the audio to text using Gemini 2.5 Flash
      const transcribedText = await transcribeAudio(blob);
      if (transcribedText) {
        // 2. Set the text to the input field so user can see/edit it before sending
        setInput(transcribedText);
      }
    } catch (e) {
      console.error("Transcription error:", e);
      alert("Could not transcribe audio. Please try again or type your message.");
    } finally {
      setIsTranscribing(false);
      setIsLoading(false);
    }
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-50 bg-black/50 backdrop-blur-sm flex items-end sm:items-center justify-center p-0 sm:p-4">
      <div className="bg-white w-full h-[90vh] sm:h-[600px] sm:max-w-md rounded-t-2xl sm:rounded-2xl flex flex-col shadow-2xl overflow-hidden animate-slide-up">
        {/* Header */}
        <div className="bg-green-600 p-4 flex justify-between items-center text-white shrink-0">
          <div className="flex items-center space-x-2">
            <span className="text-2xl">🤖</span>
            <div>
              <h3 className="font-bold">Kisan Sahayak</h3>
              <p className="text-xs text-green-100">Powered by Gemini 3 Pro</p>
            </div>
          </div>
          <button onClick={onClose} className="p-2 hover:bg-white/10 rounded-full transition-colors">
            <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
            </svg>
          </button>
        </div>

        {/* Messages */}
        <div ref={scrollRef} className="flex-1 overflow-y-auto p-4 space-y-4 bg-gray-50">
          {messages.map((msg, idx) => (
            <div key={idx} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
              <div className={`max-w-[85%] rounded-2xl p-3 text-sm leading-relaxed shadow-sm ${
                msg.role === 'user' 
                  ? 'bg-green-600 text-white rounded-br-none' 
                  : 'bg-white text-gray-800 border border-gray-200 rounded-bl-none'
              }`}>
                {msg.text}
              </div>
            </div>
          ))}
          {isLoading && !isTranscribing && (
            <div className="flex justify-start">
              <div className="bg-white p-3 rounded-2xl rounded-bl-none border border-gray-200 flex space-x-1">
                <div className="w-2 h-2 bg-green-500 rounded-full animate-bounce"></div>
                <div className="w-2 h-2 bg-green-500 rounded-full animate-bounce delay-100"></div>
                <div className="w-2 h-2 bg-green-500 rounded-full animate-bounce delay-200"></div>
              </div>
            </div>
          )}
        </div>

        {/* Input area with Audio transcription button */}
        <div className="p-3 bg-white border-t border-gray-200 flex flex-col space-y-2 shrink-0">
          {isTranscribing && (
            <div className="text-xs text-green-600 font-semibold px-2 flex items-center space-x-2">
              <span className="relative flex h-2 w-2">
                <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-green-400 opacity-75"></span>
                <span className="relative inline-flex rounded-full h-2 w-2 bg-green-500"></span>
              </span>
              <span>Transcribing voice...</span>
            </div>
          )}
          <div className="flex items-center space-x-2">
            <AudioRecorder onRecordingComplete={handleAudioTranscription} isProcessing={isLoading} />
            <input
              type="text"
              value={input}
              onChange={(e) => setInput(e.target.value)}
              onKeyPress={(e) => e.key === 'Enter' && handleSend()}
              placeholder={isTranscribing ? "Transcribing..." : "Ask anything or use mic..."}
              className="flex-1 bg-gray-100 rounded-full px-4 py-3 text-sm focus:outline-none focus:ring-2 focus:ring-green-500 transition-all"
              disabled={isLoading}
            />
            <button 
              onClick={() => handleSend()}
              disabled={!input.trim() || isLoading}
              className="p-3 bg-green-600 text-white rounded-full hover:bg-green-700 disabled:opacity-50 transition-colors shadow-sm"
            >
              <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 19l9 2-9-18-9 18 9-2zm0 0v-8" />
              </svg>
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

import { GoogleGenAI, Modality } from "@google/genai";
import { AppMode } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

/**
 * Helper to convert Blob/File to Base64
 */
const blobToBase64 = (blob: Blob): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onloadend = () => {
      if (typeof reader.result === 'string') {
        const base64Data = reader.result.split(',')[1];
        resolve(base64Data);
      } else {
        reject(new Error("Failed to read blob"));
      }
    };
    reader.onerror = reject;
    reader.readAsDataURL(blob);
  });
};

/**
 * 1. FAST RESPONSE: Daily Tip using gemini-3-flash-preview
 */
export const getDailyTip = async (): Promise<string> => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: "Provide a very short, one-sentence practical farming tip for today in Marathi and English.",
    });
    return response.text || "Keep your fields clean and monitor water levels.";
  } catch (e) {
    console.warn("Flash Tip Error", e);
    return "Farm with care today!";
  }
};

/**
 * 2. DIAGNOSTICS: Image/Video Analysis using gemini-3-pro-preview with THINKING
 */
export const analyzeDiagnosticMedia = async (file: File, mode: AppMode): Promise<string> => {
  const base64Data = await blobToBase64(file);
  const mimeType = file.type;

  let systemInstructionText = "You are Kisan-Rakshak AI. ";
  switch (mode) {
    case AppMode.ANIMAL_BEHAVIOR:
      systemInstructionText += "Analyze animal behavior/kinematics for stress/pain.";
      break;
    case AppMode.VET_DERM:
      systemInstructionText += "Analyze skin/dermatological issues in animals.";
      break;
    case AppMode.CROP_DOCTOR:
      systemInstructionText += "Analyze plant pathology (leaves/fruits).";
      break;
  }

  systemInstructionText += `
    \nOUTPUT FORMAT (Markdown):
    Use bold headings (###) and bullet points (*) for clarity.

    ### Diagnosis (निदान)
    ...

    ### Severity (तीव्रता)
    ...

    ### Immediate Action (तात्काळ उपाय)
    * ...

    ### Recommended Medicines/Products (शिफारस केलेली औषधे/उत्पादने)
    * List generic active ingredients and common Indian brand names.
    * Mention dosage if applicable.
    * Include organic/natural alternatives if available.
  `;

  // Use Gemini 3 Pro with Thinking for complex diagnosis
  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview",
    contents: {
      parts: [
        { inlineData: { data: base64Data, mimeType } },
        { text: "Analyze this strictly according to medical/agricultural protocols." }
      ]
    },
    config: {
      systemInstruction: systemInstructionText,
      thinkingConfig: { thinkingBudget: 32768 } // High thinking budget for accuracy
    }
  });

  return response.text || "Could not analyze.";
};

/**
 * 3. SEARCH: Market Insights using gemini-3-flash-preview with Google Search
 */
export const getMarketInsights = async (query: string): Promise<{text: string, urls: any[]}> => {
  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `Find current market prices and news for: ${query}. Summarize in Marathi and English. Use Markdown formatting.`,
    config: {
      tools: [{ googleSearch: {} }]
    }
  });

  const urls = response.candidates?.[0]?.groundingMetadata?.groundingChunks
    ?.map((c: any) => c.web ? { title: c.web.title, uri: c.web.uri } : null)
    .filter(Boolean) || [];

  return { text: response.text || "No info found.", urls };
};

/**
 * 4. TTS: Generate Speech from Text using gemini-2.5-flash-preview-tts
 */
export const generateSpeech = async (text: string): Promise<string | null> => {
  // Strip special chars for TTS prompt to avoid confusion, keep it short
  // Remove markdown symbols for cleaner speech
  const cleanText = text.replace(/[#*`-]/g, '').substring(0, 400) + "..."; 

  const response = await ai.models.generateContent({
    model: "gemini-2.5-flash-preview-tts",
    contents: { parts: [{ text: cleanText }] },
    config: {
      responseModalities: [Modality.AUDIO],
      speechConfig: {
        voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Kore' } },
      },
    },
  });

  const audioPart = response.candidates?.[0]?.content?.parts?.[0];
  if (audioPart && audioPart.inlineData) {
    return audioPart.inlineData.data; // Base64 audio
  }
  return null;
};

/**
 * 5. TRANSCRIPTION: Audio to Text using gemini-3-flash-preview
 */
export const transcribeAudio = async (audioBlob: Blob): Promise<string> => {
  const base64Data = await blobToBase64(audioBlob);

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: {
      parts: [
        { inlineData: { data: base64Data, mimeType: 'audio/wav' } }, // Assuming wav from MediaRecorder
        { text: "Transcribe this audio verbatim. If it is in Marathi, translate to English as well." }
      ]
    }
  });

  return response.text || "";
};

/**
 * 6. CHATBOT: General Assistant using gemini-3-pro-preview
 */
export const chatWithAI = async (history: any[], message: string): Promise<string> => {
  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview",
    contents: [...history, { role: 'user', parts: [{ text: message }] }],
    config: {
      systemInstruction: "You are an expert Indian agricultural assistant. Answer helpfully in Marathi and English. Use Markdown for formatting."
    }
  });
  return response.text || "I am listening...";
};

