  const [groundingUrls, setGroundingUrls] = useState<any[]>([]);
  const [error, setError] = useState<string | null>(null);
  const [dailyTip, setDailyTip] = useState<string>('Loading daily tip...');
  const [showChat, setShowChat] = useState(false);
  const [audioUrl, setAudioUrl] = useState<string | null>(null);

  // History State
  const [history, setHistory] = useState<HistoryItem[]>([]);
  const [showHistory, setShowHistory] = useState(false);

  // Auth Listener
  useEffect(() => {
    const unsubscribe = onAuthStateChanged(auth, (currentUser) => {
      setUser(currentUser);
      setAuthLoading(false);
    });
    return () => unsubscribe();
  }, []);

  // Load daily tip and history on user change
  useEffect(() => {
    if (user) {
      getDailyTip().then(setDailyTip);
      const savedHistory = localStorage.getItem(`kisan_history_${user.uid}`);
      if (savedHistory) {
        try {
          setHistory(JSON.parse(savedHistory));
        } catch (e) {
          console.error("Failed to parse history", e);
        }
      }
    } else {
      setHistory([]);
    }
  }, [user]);

  // Save history helper
  const saveToHistory = (mode: AppMode, text: string, urls: any[] = []) => {
    if (!user) return;
    const newItem: HistoryItem = {
      id: Date.now().toString(),
      timestamp: Date.now(),
      mode: mode,
      result: text,
      groundingUrls: urls,
      previewText: text.substring(0, 150) + "..."
    };

    const updatedHistory = [newItem, ...history].slice(0, 20); // Keep last 20
    setHistory(updatedHistory);
    localStorage.setItem(`kisan_history_${user.uid}`, JSON.stringify(updatedHistory));
  };

  const handleModeSelect = (mode: ModeConfig) => {
    setActiveMode(mode);
    resetState();
  };

  const handleBack = () => {
    setActiveMode(null);
    resetState();
  };

  const resetState = () => {
    setFile(null);
    setSearchQuery('');
    setResult(null);
    setGroundingUrls([]);
    setError(null);
    setIsLoading(false);
    setAudioUrl(null);
  };

  const handleFileSelect = useCallback((selectedFile: File) => {
    if (selectedFile.size > 20 * 1024 * 1024) {
        setError("File too large (>20MB).");
        return;
    }
    setFile(selectedFile);
    setError(null);
  }, []);

  const playTTS = async () => {
    if (!result || audioUrl) return; 
    setIsLoading(true);
    try {
      const audioBase64 = await generateSpeech(result);
      if (audioBase64) {
        const url = `data:audio/mp3;base64,${audioBase64}`;
        setAudioUrl(url);
        new Audio(url).play();
      }
    } catch (e) {
      console.error(e);
    } finally {
      setIsLoading(false);
    }
  };

  const handleAnalyze = async () => {
    if (!activeMode) return;
    setIsLoading(true);
    setError(null);
    setResult(null);
    setAudioUrl(null);

    try {
      let analysisText = "";
      let urls: any[] = [];

      if (activeMode.id === AppMode.MARKET_INSIGHTS) {
        if (!searchQuery.trim()) throw new Error("Please enter a crop or market name.");
        const data = await getMarketInsights(searchQuery);
        analysisText = data.text;
        urls = data.urls;
      } else {
        if (!file) throw new Error("Please upload a file.");
        analysisText = await analyzeDiagnosticMedia(file, activeMode.id);
      }

      setResult(analysisText);
      setGroundingUrls(urls);
      saveToHistory(activeMode.id, analysisText, urls);

    } catch (err: any) {
      setError(err.message || "Error occurred.");
    } finally {
      setIsLoading(false);
    }
  };

  const restoreHistoryItem = (item: HistoryItem) => {
    const modeConfig = MODES.find(m => m.id === item.mode);
    if (modeConfig) {
      setActiveMode(modeConfig);
      setResult(item.result);
      setGroundingUrls(item.groundingUrls || []);
      setFile(null);
      setShowHistory(false);
    }
  };

  if (authLoading) {
    return <div className="h-screen flex items-center justify-center bg-green-50"><Spinner /></div>;
  }

  if (!user) {
    return (
      <div className="min-h-screen bg-green-50 flex flex-col items-center justify-center p-4">
