          <div className="text-6xl mb-4">🌾</div>
          <h1 className="text-3xl font-bold text-green-800">Kisan-Rakshak AI</h1>
          <p className="text-gray-600">
            Welcome to your intelligent farming partner. Diagnostic tools for crops and livestock at your fingertips.
            <br/><span className="font-semibold">आपल्या शेतीचा स्मार्ट सोबती.</span>
          </p>
          <button
            onClick={signInWithGoogle}
            className="w-full flex items-center justify-center space-x-3 bg-white border border-gray-300 py-3 rounded-xl hover:bg-gray-50 transition-colors shadow-sm active:scale-95 transform"
          >
            <img src="https://www.gstatic.com/firebasejs/ui/2.0.0/images/auth/google.svg" alt="Google" className="w-6 h-6" />
            <span className="font-semibold text-gray-700">Sign in with Google</span>
          </button>
          <p className="text-xs text-gray-400">Secure access powered by Firebase Auth</p>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col font-sans pb-20 sm:pb-0">

      {/* Mobile Sticky Header */}
      <header className="bg-white/95 backdrop-blur-sm sticky top-0 z-20 border-b border-gray-100">
        <div className="max-w-7xl mx-auto px-4 h-14 flex items-center justify-between">
          <div className="flex items-center space-x-2 cursor-pointer" onClick={handleBack}>
            <span className="text-2xl">🚜</span>
            <h1 className="text-lg font-bold text-green-800">Kisan-Rakshak</h1>
          </div>

          <div className="flex items-center space-x-3">
             <button 
               onClick={() => setShowHistory(true)}
               className="p-2 text-green-700 hover:bg-green-50 rounded-full transition-colors"
               title="History"
             >
                <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z" />
                </svg>
             </button>
             <div className="flex items-center space-x-2 border-l pl-3 border-gray-100">
               {user.photoURL && (
                 <img src={user.photoURL} alt="User" className="w-8 h-8 rounded-full border border-green-200" />
