/**
 * 2. DIAGNOSTICS: Professional Medical/Agricultural Protocol Prompting
 */
export const analyzeDiagnosticMedia = async (file: File, mode: AppMode): Promise<string> => {
  const base64Data = await blobToBase64(file);
  const mimeType = file.type;

  let context = "";
  switch (mode) {
    case AppMode.ANIMAL_BEHAVIOR:
      context = "Veterinary Ethologist analyzing animal kinematics and gait for stress or physical trauma.";
      break;
    case AppMode.VET_DERM:
      context = "Veterinary Dermatologist specializing in tropical livestock diseases (Lumpy Skin, FMD, Tick-borne fever).";
      break;
    case AppMode.CROP_DOCTOR:
      context = "Plant Pathologist specializing in Indian cash crops (Sugar cane, Cotton, Turmeric, Grapes).";
      break;
  }

  const protocolPrompt = `
    ROLE: You are ${context}.
    TASK: Provide a high-precision diagnostic report based on the provided media.

    LANGUAGES: MUST provide response in MARATHI (Primary) and ENGLISH (Secondary).

    STRUCTURE:
    1. **Diagnosis (निदान)**: Clear name of the issue.
    2. **Clinical Signs (लक्षणे)**: What you observe in the image/video.
    3. **Severity (तीव्रता)**: [Low/Medium/High/Critical].
    4. **Action Plan (तात्काळ कृती)**: Step-by-step home remedies or field actions.
    5. **Medicinal/Biological Control (औषधोपचार)**: Generic names and local Indian alternatives.
    6. **Prognosis (भविष्यातील काळजी)**: Prevention tips.
  `;

  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview",
    contents: {
      parts: [
        { inlineData: { data: base64Data, mimeType } },
        { text: protocolPrompt }
      ]
    },
    config: {
      thinkingConfig: { thinkingBudget: 32768 } // Critical for medical-grade accuracy
    }
  });

  return response.text || "Diagnostic failed. Please try a clearer image.";
};

/**
 * 3. SEARCH: Market Insights with Google Search Tooling
 */
export const getMarketInsights = async (query: string): Promise<{text: string, urls: any[]}> => {
  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `Retrieve current APMC market rates, trends, and agriculture news for: ${query}. Summarize in Marathi and English.`,
    config: {
      tools: [{ googleSearch: {} }]
    }
  });

  const urls = response.candidates?.[0]?.groundingMetadata?.groundingChunks
    ?.map((c: any) => c.web ? { title: c.web.title, uri: c.web.uri } : null)
    .filter(Boolean) || [];

  return { text: response.text || "No current data found.", urls };
};

/**
 * 4. TTS: Multilingual Audio Generation
 */
export const generateSpeech = async (text: string): Promise<string | null> => {
  // Extract just the Marathi parts or first few sentences for cleaner speech
  const cleanText = text.replace(/[#*`-]/g, '').substring(0, 500); 

  const response = await ai.models.generateContent({
    model: "gemini-2.5-flash-preview-tts",
    contents: { parts: [{ text: `Read this diagnosis clearly: ${cleanText}` }] },
    config: {
      responseModalities: [Modality.AUDIO],
      speechConfig: {
        voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Kore' } },
      },
    },
  });

  const audioPart = response.candidates?.[0]?.content?.parts?.[0];
  return audioPart?.inlineData?.data || null;
};

export const chatWithAI = async (history: any[], message: string): Promise<string> => {
  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview",
    contents: [...history, { role: 'user', parts: [{ text: message }] }],
    config: {
      systemInstruction: "You are the Kisan-Rakshak Concierge. Assist with farming queries in Marathi and English."
    }
  });
  return response.text || "How can I help you today?";
};

export const transcribeAudio = async (audioBlob: Blob): Promise<string> => {
  const base64Data = await blobToBase64(audioBlob);
  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: {
      parts: [
        { inlineData: { data: base64Data, mimeType: 'audio/wav' } },
        { text: "Transcribe this farmer query verbatim." }
      ]
    }
  });
  return response.text || "";
};

