import React, { useState, useRef, useEffect } from 'react';
import { ChatMessage, Language } from '../types';
import { chatWithAI, transcribeAudio } from '../services/geminiService';
import { AudioRecorder } from './AudioRecorder';

interface ChatInterfaceProps {
  isOpen: boolean;
  onClose: () => void;
  currentLanguage: Language;
}

export const ChatInterface: React.FC<ChatInterfaceProps> = ({ isOpen, onClose, currentLanguage }) => {
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [isTranscribing, setIsTranscribing] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  // Initialize welcome message when language changes
  useEffect(() => {
    if (messages.length === 0 || messages[0].role === 'model') {
       const welcomeText = currentLanguage.code === 'en' 
         ? "Namaste! I am Kisan-Rakshak Assistant. Ask me anything about your farm."
         : `नमस्ते! मी किसान-रक्षक साहाय्यक आहे. आपल्या शेतीबद्दल काहीही विचारा. (In ${currentLanguage.name})`;
       setMessages([{ role: 'model', text: welcomeText }]);
    }
  }, [currentLanguage]);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, isOpen]);

  const handleSend = async (textToSend?: string) => {
    const text = textToSend || input;
    if (!text.trim() || isLoading) return;

    const userMsg: ChatMessage = { role: 'user', text: text };
    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsLoading(true);

    try {
      const history = messages.map(m => ({ role: m.role, parts: [{ text: m.text }] }));
      const responseText = await chatWithAI(history, text, currentLanguage);
      setMessages(prev => [...prev, { role: 'model', text: responseText }]);
    } catch (e: any) {
      const errorMsg = e?.status === 500 
        ? "The server is busy right now. Please try again in a moment."
        : "Sorry, I encountered an issue. Please try again.";
      setMessages(prev => [...prev, { role: 'model', text: errorMsg }]);
    } finally {
      setIsLoading(false);
    }
  };

  const handleAudioTranscription = async (blob: Blob) => {
    setIsTranscribing(true);
    setIsLoading(true);
    try {
      const transcribedText = await transcribeAudio(blob);
      if (transcribedText) {
        setInput(transcribedText);
      }
    } catch (e) {
      console.error("Transcription error:", e);
      alert("Could not transcribe audio. Please try again or type your message.");
    } finally {
      setIsTranscribing(false);
      setIsLoading(false);
    }
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-50 bg-black/50 backdrop-blur-sm flex items-end sm:items-center justify-center p-0 sm:p-4">
      <div className="bg-white w-full h-[90vh] sm:h-[600px] sm:max-w-md rounded-t-2xl sm:rounded-2xl flex flex-col shadow-2xl overflow-hidden animate-slide-up">
        <div className="bg-agri-forest p-4 flex justify-between items-center text-white shrink-0">
          <div className="flex items-center space-x-2">
            <span className="text-2xl">🤖</span>
            <div>
              <h3 className="font-bold font-serif">Kisan Sahayak</h3>
              <p className="text-[10px] uppercase font-bold text-agri-clay tracking-widest">In {currentLanguage.nativeName} (Gemini 3 Flash)</p>
            </div>
          </div>
          <button onClick={onClose} className="p-2 hover:bg-white/10 rounded-full transition-colors">
            <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
            </svg>
          </button>
        </div>

        <div ref={scrollRef} className="flex-1 overflow-y-auto p-4 space-y-4 bg-agri-ivory custom-scrollbar">
          {messages.map((msg, idx) => (
            <div key={idx} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
              <div className={`max-w-[85%] rounded-2xl p-4 text-sm leading-relaxed shadow-sm ${
                msg.role === 'user' 
                  ? 'bg-agri-forest text-white rounded-br-none' 
                  : 'bg-white text-agri-forest border border-agri-sand rounded-bl-none font-medium'
              }`}>
                {msg.text}
              </div>
            </div>
          ))}
          {isLoading && !isTranscribing && (
            <div className="flex justify-start">
              <div className="bg-white p-4 rounded-2xl rounded-bl-none border border-agri-sand flex space-x-1">
                <div className="w-2 h-2 bg-agri-clay rounded-full animate-bounce"></div>
                <div className="w-2 h-2 bg-agri-clay rounded-full animate-bounce delay-100"></div>
                <div className="w-2 h-2 bg-agri-clay rounded-full animate-bounce delay-200"></div>
              </div>
            </div>
          )}
        </div>

        <div className="p-4 bg-white border-t border-agri-sand flex flex-col space-y-3 shrink-0">
          {isTranscribing && (
            <div className="text-[10px] text-agri-moss font-black uppercase tracking-widest px-2 flex items-center space-x-2">
              <span className="relative flex h-2 w-2">
                <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-agri-clay opacity-75"></span>
                <span className="relative inline-flex rounded-full h-2 w-2 bg-agri-clay"></span>
              </span>
              <span>Processing Voice...</span>
            </div>
          )}
          <div className="flex items-center space-x-2">
            <AudioRecorder onRecordingComplete={handleAudioTranscription} isProcessing={isLoading} />
            <input
              type="text"
              value={input}
              onChange={(e) => setInput(e.target.value)}
              onKeyPress={(e) => e.key === 'Enter' && handleSend()}
              placeholder={isTranscribing ? "Transcribing..." : "Ask in native script or English..."}
              className="flex-1 bg-agri-ivory border border-agri-sand rounded-full px-5 py-3 text-sm focus:outline-none focus:ring-2 focus:ring-agri-clay/50 transition-all font-medium"
              disabled={isLoading}
            />
            <button onClick={() => handleSend()} disabled={!input.trim() || isLoading} className="p-3 bg-agri-forest text-white rounded-full hover:bg-agri-moss disabled:opacity-30 transition-all shadow-lg active:scale-90">
              <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 19l9 2-9-18-9 18 9-2zm0 0v-8" />
              </svg>
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import ReactMarkdown from 'react-markdown';
import { AppMode, ModeConfig, HistoryItem, Language, SUPPORTED_LANGUAGES } from './types';
import { ModeCard } from './components/ModeCard';
import { FileUpload } from './components/FileUpload';
import { ChatInterface } from './components/ChatInterface';
import { HistoryModal } from './components/HistoryModal';
import { 
  analyzeDiagnosticMedia, 
  getDailyTip, 
  generateSpeech,
  getMarketInsights,
  playPCM
} from './services/geminiService';

const MODES: ModeConfig[] = [
  {
    id: AppMode.CROP_DOCTOR,
    title: 'Crop Doctor',
    description: 'Pathology & nutrient deficiency scanning.',
    icon: '🌱',
    acceptedFileTypes: 'image/*',
    inputLabel: 'Scan Leaf',
  },
  {
    id: AppMode.VET_DERM,
    title: 'Derm-Scan',
    description: 'Advanced livestock skin & lesion diagnostics.',
    icon: '🐄',
    acceptedFileTypes: 'image/*',
    inputLabel: 'Diagnostic Photo',
  },
  {
    id: AppMode.ANIMAL_BEHAVIOR,
    title: 'Animal Pulse',
    description: 'Kinematic stress & pain detection.',
    icon: '🐕',
    acceptedFileTypes: 'video/*,image/gif',
    inputLabel: 'Behavior Analysis',
  },
  {
    id: AppMode.MARKET_INSIGHTS,
    title: 'Market Intelligence',
    description: 'Real-time commodity prices & news.',
    icon: '📈',
    inputLabel: '',
    acceptedFileTypes: ''
  }
];

const App: React.FC = () => {
  const [activeMode, setActiveMode] = useState<ModeConfig | null>(null);
  const [file, setFile] = useState<File | null>(null);
  const [searchQuery, setSearchQuery] = useState('');
  const [isScanning, setIsScanning] = useState(false);
  const [scanProgress, setScanProgress] = useState(0);
  const [scanStatus, setScanStatus] = useState('Detecting patterns...');
  const [result, setResult] = useState<string | null>(null);
  const [groundingUrls, setGroundingUrls] = useState<any[]>([]);
  const [error, setError] = useState<string | null>(null);
  const [language, setLanguage] = useState<Language>(SUPPORTED_LANGUAGES[0]);
  const [dailyTip, setDailyTip] = useState<string>('Harvesting today\'s tip...');
  const [showChat, setShowChat] = useState(false);
  const [history, setHistory] = useState<HistoryItem[]>([]);
  const [showHistory, setShowHistory] = useState(false);

  useEffect(() => {
    getDailyTip(language).then(setDailyTip);
    const savedHistory = localStorage.getItem('kisan_history');
    if (savedHistory) {
      try {
        setHistory(JSON.parse(savedHistory));
      } catch (e) {
        console.error("Failed to parse history", e);
      }
    }
  }, [language]);

  const saveToHistory = (mode: AppMode, text: string, urls: any[] = []) => {
    const newItem: HistoryItem = {
      id: Date.now().toString(),
      timestamp: Date.now(),
      mode: mode,
      result: text,
      groundingUrls: urls,
      previewText: text.substring(0, 150) + "..."
    };
    const updatedHistory = [newItem, ...history].slice(0, 20);
    setHistory(updatedHistory);
    localStorage.setItem('kisan_history', JSON.stringify(updatedHistory));
  };

  const resetState = () => {
    setFile(null);
    setSearchQuery('');
    setResult(null);
    setGroundingUrls([]);
    setError(null);
    setIsScanning(false);
    setScanProgress(0);
  };

  const handleAnalyze = async () => {
    if (!activeMode) return;
    setIsScanning(true);
    setError(null);

    // Simulate progress while calling API
    const statuses = [
      'Detecting leaf patterns',
      'Analyzing color variations',
      'Identifying disease markers',
      'Cross-referencing database',
      'Generating diagnosis'
    ];

    let progress = 0;
    const progressInterval = setInterval(() => {
      progress += Math.floor(Math.random() * 5) + 2;
      if (progress > 95) progress = 95;
      setScanProgress(progress);
      setScanStatus(statuses[Math.floor(progress / 20)] || statuses[statuses.length - 1]);
    }, 200);

    try {
      let analysisText = "";
      let urls: any[] = [];
      if (activeMode.id === AppMode.MARKET_INSIGHTS) {
        const data = await getMarketInsights(searchQuery, language);
        analysisText = data.text;
        urls = data.urls;
      } else {
        if (!file) throw new Error("Please select a diagnostic file.");
        analysisText = await analyzeDiagnosticMedia(file, activeMode.id, language);
      }

      clearInterval(progressInterval);
      setScanProgress(100);
      setScanStatus('Done!');

      setTimeout(() => {
        setResult(analysisText);
        setGroundingUrls(urls);
        saveToHistory(activeMode.id, analysisText, urls);
        setIsScanning(false);
      }, 500);

    } catch (err: any) {
      clearInterval(progressInterval);
      setIsScanning(false);
      setError(err.message || "An unexpected error occurred.");
    }
  };

  const handleShare = async (text: string) => {
    if (!text) return;
    const shareData = {
      title: 'Krishi Rakshak AI Report',
      text: `Krishi Rakshak AI Report:\n\n${text.substring(0, 300)}...\n\nView full report on Krishi Rakshak.`,
      url: window.location.origin
    };
    try {
      if (navigator.share) {
        await navigator.share(shareData);
      } else {
        await navigator.clipboard.writeText(`Krishi Rakshak AI Report:\n\n${text}`);
        alert("Report copied to clipboard!");
      }
    } catch (err) {
      console.error("Error sharing:", err);
    }
  };

  const restoreHistoryItem = (item: HistoryItem) => {
    const modeConfig = MODES.find(m => m.id === item.mode);
    if (modeConfig) {
      setActiveMode(modeConfig);
      setResult(item.result);
      setGroundingUrls(item.groundingUrls || []);
      setFile(null);
      setShowHistory(false);
    }
