        <div className="max-w-2xl mx-auto px-6 h-16 flex items-center justify-between">
          <div className="flex items-center space-x-3 cursor-pointer" onClick={() => { setActiveMode(null); resetState(); }}>
             <div className="w-10 h-10 bg-gradient-to-br from-emerald-400 to-teal-500 rounded-full flex items-center justify-center shadow-lg text-lg">
               🌾
             </div>
             <div>
               <h1 className="text-lg font-bold text-emerald-800 leading-none">Krishi Rakshak</h1>
               <p className="text-[10px] uppercase font-bold text-emerald-600 tracking-wider">AI Crop Doctor</p>
             </div>
          </div>

          <div className="flex items-center space-x-2">
             <div className="relative group">
               <button className="flex items-center space-x-2 px-3 py-2 bg-white border border-emerald-100 rounded-xl text-xs font-bold text-emerald-800 hover:border-emerald-500 transition-all shadow-sm">
                 <span className="text-sm">🌐</span>
                 <span>{language.nativeName}</span>
               </button>
               <div className="absolute right-0 top-full mt-2 w-48 bg-white border border-emerald-100 rounded-2xl shadow-2xl opacity-0 invisible group-hover:opacity-100 group-hover:visible transition-all z-50 overflow-hidden">
                 <div className="max-h-64 overflow-y-auto custom-scrollbar">
                   {SUPPORTED_LANGUAGES.map((lang) => (
                     <button
                       key={lang.code}
                       onClick={() => setLanguage(lang)}
