                     >
                       <span>{lang.nativeName}</span>
                       <span className="text-[10px] text-emerald-400 uppercase font-black">{lang.name}</span>
                     </button>
                   ))}
                 </div>
               </div>
             </div>
          </div>
        </div>
      </header>

      <main className="flex-grow max-w-2xl mx-auto w-full px-4 py-6">
        {!activeMode && !result && !isScanning && (
          <div className="space-y-6 animate-fade-in">
            {/* Weather Widget */}
            <div className="glass rounded-3xl p-5 shadow-lg border border-white/50 bg-gradient-to-r from-emerald-500/5 to-teal-500/5">
              <div className="flex items-center justify-between">
