import React from 'react';
import { HistoryItem, AppMode } from '../types';

interface HistoryModalProps {
  isOpen: boolean;
  onClose: () => void;
  history: HistoryItem[];
  onSelect: (item: HistoryItem) => void;
  onShare: (text: string) => void;
