}

const getModeIcon = (mode: AppMode) => {
  switch (mode) {
    case AppMode.CROP_DOCTOR: return '🌱';
    case AppMode.VET_DERM: return '🐄';
    case AppMode.ANIMAL_BEHAVIOR: return '🐕';
    case AppMode.MARKET_INSIGHTS: return '📈';
    case AppMode.DIRECT_MARKET: return '🏪';
    default: return '📄';
