                      {new Date(item.timestamp).toLocaleDateString()}
                    </span>
                  </div>
                  <h4 className="font-bold text-emerald-900 group-hover:text-emerald-600 transition-colors line-clamp-1 mb-1">
                    {item.previewText.split('\n')[0].replace(/\*\*/g, '') || "Untitled Report"}
