              <button 
                onClick={() => { setRole(UserRole.CONSUMER); setActiveMode(null); setIsAddingListing(false); }}
                className={`px-4 py-1.5 rounded-xl text-xs font-bold transition-all ${role === UserRole.CONSUMER ? 'bg-emerald-900 text-white shadow-md' : 'text-emerald-800'}`}
              >
                Consumer
              </button>
            </div>
          </div>
        </div>
      </header>

      <main className="flex-grow max-w-2xl mx-auto w-full p-4 py-6">

        {/* FARMER INTERFACE */}
        {role === UserRole.FARMER && !activeMode && !isAddingListing && !result && (
          <div className="space-y-8 animate-fade-in">
            <div className="glass p-5 rounded-3xl border border-emerald-100 flex items-center justify-between bg-gradient-to-r from-emerald-50 to-white">
              <div>
                <p className="text-[10px] uppercase font-black tracking-widest text-emerald-500 mb-1">Today's Wisdom</p>
                <p className="text-sm font-bold text-emerald-900 italic">"{dailyTip}"</p>
              </div>
              <div className="text-3xl">💡</div>
