              </h2>
              <button 
                onClick={() => setIsAddingListing(true)}
                className="w-full p-6 bg-white border-2 border-dashed border-emerald-200 rounded-[2.5rem] flex flex-col items-center gap-2 group hover:border-emerald-500 transition-all"
              >
                <div className="w-14 h-14 bg-emerald-50 rounded-2xl flex items-center justify-center text-3xl group-hover:scale-110 transition-transform">🏪</div>
                <div className="text-center">
                  <p className="font-bold text-emerald-900">Add New Listing</p>
                  <p className="text-xs text-emerald-500 font-medium">Sell your dairy & vegetables directly</p>
                </div>
              </button>
            </section>
          </div>
