             </div>
             <div className="glass p-6 rounded-4xl shadow-2xl space-y-6 border border-emerald-100">
                <div className="prose prose-emerald prose-sm max-w-none text-emerald-900 font-medium leading-relaxed">
                   <ReactMarkdown>{result}</ReactMarkdown>
                </div>
                <button 
                  onClick={async () => {
                    const audio = await generateSpeech(result, language);
                    if (audio) playPCM(audio);
                  }}
                  className="w-full py-4 bg-emerald-900 text-white rounded-2xl font-bold flex items-center justify-center gap-3"
