      </main>

      {/* Scanning Overlay */}
      {isScanning && (
        <div className="fixed inset-0 z-[100] bg-emerald-950/90 flex flex-col items-center justify-center p-8">
           <div className="w-64 h-64 border-4 border-emerald-400/20 rounded-full flex items-center justify-center animate-pulse mb-8">
              <span className="text-8xl">🧬</span>
              <div className="absolute inset-0 scan-line bg-gradient-to-r from-transparent via-emerald-400 to-transparent h-1 w-full shadow-[0_0_15px_#10b981]"></div>
           </div>
           <p className="text-white text-2xl font-bold mb-2">KrishiX AI Processing</p>
