export const LISTINGS_COLLECTION = "listings";
export const HISTORY_COLLECTION = "history";

export const addListing = async (listing: any) => {
  return addDoc(collection(db, LISTINGS_COLLECTION), {
    ...listing,
    createdAt: new Date().toISOString()
  });
};

export const addHistory = async (historyItem: any) => {
  return addDoc(collection(db, HISTORY_COLLECTION), {
    ...historyItem,
    createdAt: new Date().toISOString()
  });
};

export const getHistory = async () => {
  const q = query(collection(db, HISTORY_COLLECTION), orderBy("timestamp", "desc"), limit(20));
  const querySnapshot = await getDocs(q);
  return querySnapshot.docs.map(doc => ({ id: doc.id, ...doc.data() }));
};

