export const LISTINGS_COLLECTION = "listings";
export const HISTORY_COLLECTION = "history";
export const USERS_COLLECTION = "users";

// Auth Functions
export const loginWithGoogle = async () => {
  try {
    const result = await signInWithPopup(auth, googleProvider);
    return result.user;
  } catch (error) {
    console.error("Login failed:", error);
    throw error;
  }
};

export const logout = () => signOut(auth);

// User Profile Functions
export const getUserProfile = async (uid: string) => {
  const userDoc = await getDoc(doc(db, USERS_COLLECTION, uid));
  return userDoc.exists() ? userDoc.data() : null;
};

export const setUserProfile = async (uid: string, data: any) => {
  await setDoc(doc(db, USERS_COLLECTION, uid), data, { merge: true });
};

// Data Functions
export const addListing = async (listing: any) => {
  return addDoc(collection(db, LISTINGS_COLLECTION), {
    ...listing,
    createdAt: new Date().toISOString()
  });
};

export const addHistory = async (historyItem: any) => {
  return addDoc(collection(db, HISTORY_COLLECTION), {
    ...historyItem,
    createdAt: new Date().toISOString()
  });
};

export const getHistoryByUserId = (uid: string, callback: (data: any[]) => void) => {
  const q = query(
    collection(db, HISTORY_COLLECTION), 
    where("userId", "==", uid),
    orderBy("timestamp", "desc"), 
    limit(20)
  );
  return onSnapshot(q, (snapshot) => {
    const data = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() }));
    callback(data);
  });
};

