        <h1 className="text-4xl font-black text-emerald-900 tracking-tight mb-4">KrishiX</h1>
        <p className="text-emerald-600 font-medium mb-12 max-w-xs">AI-Powered Precision Agriculture & Sustainable Farming Hub</p>
