                    const audio = await generateSpeech(result, language);
                    if (audio) playPCM(audio);
                  }}
                  className="w-full py-5 bg-emerald-900 text-white rounded-2xl font-bold flex items-center justify-center gap-4 shadow-xl hover:bg-emerald-800 transition-all active:scale-95"
                >
                  <span className="text-2xl">🔊</span> 
                  <span>Read Report Aloud</span>
                </button>
             </div>
          </div>
        )}
      </main>

      {isScanning && (
        <div className="fixed inset-0 z-[100] bg-emerald-950/95 flex flex-col items-center justify-center p-8 backdrop-blur-sm">
           <div className="w-72 h-72 border-4 border-emerald-400/20 rounded-full flex items-center justify-center animate-pulse mb-10 relative">
              <div className="absolute inset-0 rounded-full border-t-4 border-emerald-400 animate-spin"></div>
              <span className="text-8xl">🧬</span>
              <div className="absolute inset-x-0 top-1/2 scan-line bg-gradient-to-r from-transparent via-emerald-400 to-transparent h-1.5 w-full shadow-[0_0_20px_#10b981]"></div>
           </div>
           <p className="text-white text-3xl font-black mb-2 tracking-tight">KrishiX Intelligence</p>
           <p className="text-emerald-400 font-bold uppercase tracking-[0.3em] text-xs animate-pulse">Running Neural Diagnostics...</p>
        </div>
      )}

      <div className="fixed bottom-8 right-8 flex flex-col gap-5 z-40">
        <button 
          onClick={() => setShowHistory(true)}
          className="w-16 h-16 bg-white border-2 border-emerald-50 text-emerald-900 rounded-[1.5rem] shadow-2xl flex items-center justify-center transform hover:scale-110 active:scale-95 transition-all group"
