import React, { useState, useEffect } from 'react';
import ReactMarkdown from 'react-markdown';
import { AppMode, ModeConfig, HistoryItem, Language, SUPPORTED_LANGUAGES, UserRole, Listing } from './types';
import { ModeCard } from './components/ModeCard';
import { FileUpload } from './components/FileUpload';
import { ChatInterface } from './components/ChatInterface';
import { HistoryModal } from './components/HistoryModal';
import { 
  analyzeDiagnosticMedia, 
  getDailyTip, 
  generateSpeech,
  getMarketInsights,
  playPCM
} from './services/geminiService';
import { db, addListing, addHistory, LISTINGS_COLLECTION, HISTORY_COLLECTION } from './services/firebaseService';
import { collection, query, orderBy, onSnapshot, limit } from 'firebase/firestore';

const AI_MODES: ModeConfig[] = [
  {
    id: AppMode.CROP_DOCTOR,
    title: 'Crop Doctor',
    description: 'Pathology & nutrient scanning.',
    icon: '🌱',
    acceptedFileTypes: 'image/*',
    inputLabel: 'Scan Leaf',
  },
  {
    id: AppMode.VET_DERM,
    title: 'Derm-Scan',
    description: 'Livestock skin diagnostics.',
    icon: '🐄',
    acceptedFileTypes: 'image/*',
    inputLabel: 'Diagnostic Photo',
  },
  {
    id: AppMode.ANIMAL_BEHAVIOR,
    title: 'Animal Pulse',
    description: 'Stress & pain detection.',
    icon: '🐕',
    acceptedFileTypes: 'video/*,image/gif',
    inputLabel: 'Analysis',
  },
  {
    id: AppMode.MARKET_INSIGHTS,
    title: 'Market Intelligence',
    description: 'Prices & local news.',
    icon: '📈',
    inputLabel: '',
    acceptedFileTypes: ''
  }
];

const App: React.FC = () => {
  const [role, setRole] = useState<UserRole>(UserRole.FARMER);
  const [activeMode, setActiveMode] = useState<ModeConfig | null>(null);
  const [isScanning, setIsScanning] = useState(false);
  const [result, setResult] = useState<string | null>(null);
  const [language, setLanguage] = useState<Language>(SUPPORTED_LANGUAGES[0]);
  const [showLangPicker, setShowLangPicker] = useState(false);
  const [dailyTip, setDailyTip] = useState<string>('Welcome to KrishiX...');
  const [showChat, setShowChat] = useState(false);
  const [history, setHistory] = useState<HistoryItem[]>([]);
  const [showHistory, setShowHistory] = useState(false);

  // Marketplace States
  const [listings, setListings] = useState<Listing[]>([]);
  const [isAddingListing, setIsAddingListing] = useState(false);
  const [newListing, setNewListing] = useState<Partial<Listing>>({ category: 'Vegetable' });
  const [file, setFile] = useState<File | null>(null);

  useEffect(() => {
    getDailyTip(language).then(setDailyTip);

    // Real-time listener for listings
    const listingsQuery = query(collection(db, LISTINGS_COLLECTION), orderBy("createdAt", "desc"));
    const unsubscribeListings = onSnapshot(listingsQuery, (snapshot) => {
      const data = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() })) as Listing[];
      setListings(data);
    });

    // Real-time listener for history
    const historyQuery = query(collection(db, HISTORY_COLLECTION), orderBy("timestamp", "desc"), limit(20));
    const unsubscribeHistory = onSnapshot(historyQuery, (snapshot) => {
      const data = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() })) as HistoryItem[];
      setHistory(data);
    });

    return () => {
      unsubscribeListings();
      unsubscribeHistory();
    };
  }, [language]);

  const saveToHistory = async (mode: AppMode, text: string) => {
    const newItem = {
      timestamp: Date.now(),
      mode: mode,
      result: text,
      previewText: text.substring(0, 100) + "..."
    };
    try {
      await addHistory(newItem);
    } catch (e) {
      console.error("Firebase History Error:", e);
    }
  };

  const handleCreateListing = async () => {
    if (!newListing.name || !newListing.price || !file) {
      alert("Please fill all fields and upload a photo.");
      return;
    }

    setIsScanning(true);
    const reader = new FileReader();
    reader.onloadend = async () => {
      const listingData = {
        name: newListing.name!,
        price: newListing.price!,
        category: newListing.category as any,
        image: reader.result as string,
        farmerName: 'Farmer Bharat'
      };

      try {
        await addListing(listingData);
        setIsScanning(false);
        setIsAddingListing(false);
        setNewListing({ category: 'Vegetable' });
        setFile(null);
      } catch (e) {
        alert("Failed to create listing. Please try again.");
        setIsScanning(false);
      }
    };
    reader.readAsDataURL(file);
  };

  const handleAnalyze = async () => {
    if (!activeMode) return;
    setIsScanning(true);
    try {
      let analysisText = "";
      if (activeMode.id === AppMode.MARKET_INSIGHTS) {
        const data = await getMarketInsights('current market rates', language);
        analysisText = data.text;
      } else {
        if (!file) throw new Error("Select a photo.");
        analysisText = await analyzeDiagnosticMedia(file, activeMode.id, language);
      }
      setResult(analysisText);
      await saveToHistory(activeMode.id, analysisText);
    } catch (err: any) {
      alert(err.message);
    } finally {
      setIsScanning(false);
    }
  };

  return (
    <div className="min-h-screen bg-agri-ivory flex flex-col font-sans">

      {/* Role Switcher & Header */}
      <header className="glass sticky top-0 z-50 border-b border-emerald-100">
        <div className="max-w-2xl mx-auto px-4 h-20 flex items-center justify-between">
          <div className="flex items-center space-x-2 cursor-pointer" onClick={() => { setActiveMode(null); setIsAddingListing(false); setResult(null); }}>
             <div className="w-10 h-10 bg-gradient-to-br from-emerald-500 to-teal-600 rounded-full flex items-center justify-center text-xl shadow-lg">🌾</div>
             <h1 className="text-xl font-bold text-emerald-900 leading-none tracking-tight">KrishiX</h1>
          </div>

          <div className="flex items-center space-x-2">
            <button 
              onClick={() => setShowLangPicker(true)}
              className="p-2.5 bg-white border border-emerald-100 rounded-2xl shadow-sm flex items-center gap-2 hover:bg-emerald-50 transition-all group"
            >
              <span className="text-lg group-hover:rotate-12 transition-transform">🌐</span>
              <span className="text-[10px] font-black uppercase tracking-widest text-emerald-900 hidden sm:block">{language.nativeName}</span>
            </button>

            <div className="bg-emerald-50 p-1 rounded-2xl flex border border-emerald-100 shadow-inner">
              <button 
                onClick={() => { setRole(UserRole.FARMER); setActiveMode(null); setIsAddingListing(false); setResult(null); }}
                className={`px-4 py-1.5 rounded-xl text-[10px] uppercase font-black transition-all ${role === UserRole.FARMER ? 'bg-emerald-900 text-white shadow-md' : 'text-emerald-800 opacity-60'}`}
              >
                Farmer
              </button>
              <button 
                onClick={() => { setRole(UserRole.CONSUMER); setActiveMode(null); setIsAddingListing(false); setResult(null); }}
                className={`px-4 py-1.5 rounded-xl text-[10px] uppercase font-black transition-all ${role === UserRole.CONSUMER ? 'bg-emerald-900 text-white shadow-md' : 'text-emerald-800 opacity-60'}`}
              >
                Consumer
              </button>
            </div>
          </div>
        </div>
      </header>

      <main className="flex-grow max-w-2xl mx-auto w-full p-4 py-6">

        {/* FARMER INTERFACE */}
        {role === UserRole.FARMER && !activeMode && !isAddingListing && !result && (
          <div className="space-y-10 animate-fade-in">
            {/* Daily Inspiration */}
            <div className="glass p-6 rounded-[2.5rem] border border-emerald-100 flex items-center gap-6 bg-gradient-to-r from-emerald-50 to-white shadow-xl shadow-emerald-900/5">
              <div className="w-14 h-14 bg-emerald-100 rounded-2xl flex items-center justify-center text-3xl shrink-0">💡</div>
              <div className="flex-1">
                <p className="text-[10px] uppercase font-black tracking-widest text-emerald-500 mb-1">Today's Wisdom</p>
                <p className="text-sm font-bold text-emerald-900 italic leading-relaxed">"{dailyTip}"</p>
              </div>
            </div>

            {/* Section A: Agri-Expert Help */}
            <section className="space-y-4">
              <div className="flex items-center justify-between px-2">
                <h2 className="text-lg font-bold text-emerald-900 flex items-center gap-2">
                  <span className="w-2 h-6 bg-emerald-500 rounded-full"></span>
                  Agri-Expert Help
                </h2>
                <span className="text-[10px] font-black uppercase tracking-widest text-emerald-400">AI Modules</span>
              </div>
              <div className="grid grid-cols-2 gap-4">
                {AI_MODES.map(m => <ModeCard key={m.id} mode={m} onClick={setActiveMode} />)}
              </div>
            </section>

            {/* Section B: Farmer's Stall */}
            <section className="space-y-4">
              <div className="flex items-center justify-between px-2">
                <h2 className="text-lg font-bold text-emerald-900 flex items-center gap-2">
                  <span className="w-2 h-6 bg-amber-500 rounded-full"></span>
                  Farmer's Stall
                </h2>
                <span className="text-[10px] font-black uppercase tracking-widest text-amber-500">Sell Direct</span>
              </div>
              <button 
