};

export const getLocalizedAdvisory = async (lat: number, lng: number, lang: Language): Promise<{text: string, urls: any[]}> => {
  return callAiWithRetry(async () => {
    const prompt = `You are a localized agricultural expert.
    1. Search for current weather (temp, humidity, rain chance) and soil conditions for coordinates [${lat}, ${lng}].
    2. Provide a 3-step action plan for a farmer at this location for today.
    3. Use ${lang.name} and English.
    Keep it concise and practical. Use emojis.`;

    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }]
      }
    });

    const urls = response.candidates?.[0]?.groundingMetadata?.groundingChunks
      ?.map((c: any) => c.web ? { title: c.web.title, uri: c.web.uri } : null)
      .filter(Boolean) || [];

    return { text: response.text || "Unable to fetch localized data.", urls };
  });
};

export const analyzeDiagnosticMedia = async (file: File, mode: AppMode, lang: Language): Promise<string> => {
  const base64Data = await blobToBase64(file);
  const mimeType = file.type;

  let context = "";
  switch (mode) {
    case AppMode.ANIMAL_BEHAVIOR:
      context = "Veterinary Ethologist analyzing animal gait/stress.";
      break;
    case AppMode.VET_DERM:
      context = "Veterinary Dermatologist analyzing livestock skin.";
      break;
    case AppMode.CROP_DOCTOR:
      context = "Plant Pathologist analyzing crop health.";
      break;
  }

  const protocolPrompt = `
    ROLE: You are ${context}.
    TASK: Provide an instant diagnostic report.
    LANGUAGES: ${lang.name} (Primary) and English (Secondary).

    STRUCTURE:
    1. **Diagnosis (निदान)**: Name.
    2. **Clinical Signs (लक्षणे)**: Observations.
    3. **Severity (तीव्रता)**: Status.
    4. **Action Plan (तात्काळ कृती)**: Steps.
    5. **Prevention (काळजी)**: Tips.
  `;

  return callAiWithRetry(async () => {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: {
        parts: [
          { inlineData: { data: base64Data, mimeType } },
          { text: protocolPrompt }
        ]
      },
      config: { temperature: 0.4 }
    });
    return response.text || "Diagnostic failed. Please try a clearer image.";
  });
};

export const getMarketInsights = async (query: string, lang: Language): Promise<{text: string, urls: any[]}> => {
  return callAiWithRetry(async () => {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Retrieve current APMC market rates, trends, and agriculture news for: ${query}. Summarize in ${lang.name} and English.`,
      config: {
        tools: [{ googleSearch: {} }]
      }
    });
    const urls = response.candidates?.[0]?.groundingMetadata?.groundingChunks
      ?.map((c: any) => c.web ? { title: c.web.title, uri: c.web.uri } : null)
      .filter(Boolean) || [];
    return { text: response.text || "No current data found.", urls };
  });
};

export const generateSpeech = async (text: string, lang: Language): Promise<string | null> => {
  const cleanText = text.replace(/[#*`-]/g, '').substring(0, 400); 
  return callAiWithRetry(async () => {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: { parts: [{ text: `Read this in ${lang.name}: ${cleanText}` }] },
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Kore' } },
        },
      },
    });
    const audioPart = response.candidates?.[0]?.content?.parts?.[0];
    return audioPart?.inlineData?.data || null;
  }).catch(() => null);
};

export const chatWithAI = async (history: any[], message: string, lang: Language): Promise<string> => {
  return callAiWithRetry(async () => {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: [...history, { role: 'user', parts: [{ text: message }] }],
      config: {
        systemInstruction: `You are the KrishiX Concierge. Provide fast, direct answers in ${lang.name} and English.`
      }
    });
    return response.text || "How can I help you today?";
  });
};

export const transcribeAudio = async (audioBlob: Blob): Promise<string> => {
  const base64Data = await blobToBase64(audioBlob);
  return callAiWithRetry(async () => {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: {
        parts: [
          { inlineData: { data: base64Data, mimeType: 'audio/wav' } },
          { text: "Verbatim transcription of this farmer query." }
        ]
      }
    });
    return response.text || "";
  });
};

