  const [isAddingListing, setIsAddingListing] = useState(false);
  const [newListing, setNewListing] = useState<Partial<Listing>>({ category: 'Vegetable' });
  const [file, setFile] = useState<File | null>(null);

  useEffect(() => {
    getDailyTip(language).then(setDailyTip);

    // Real-time listener for listings
    const listingsQuery = query(collection(db, LISTINGS_COLLECTION), orderBy("createdAt", "desc"));
    const unsubscribeListings = onSnapshot(listingsQuery, (snapshot) => {
      const data = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() })) as Listing[];
      setListings(data);
    });

    // Real-time listener for history
    const historyQuery = query(collection(db, HISTORY_COLLECTION), orderBy("timestamp", "desc"), limit(20));
    const unsubscribeHistory = onSnapshot(historyQuery, (snapshot) => {
      const data = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() })) as HistoryItem[];
      setHistory(data);
    });

    return () => {
      unsubscribeListings();
      unsubscribeHistory();
    };
  }, [language]);

  const handleFetchLocalAdvisory = () => {
    setLocationLoading(true);
    if (!navigator.geolocation) {
      alert("Geolocation is not supported by your browser");
      setLocationLoading(false);
      return;
    }

    navigator.geolocation.getCurrentPosition(
      async (position) => {
        try {
          const { latitude, longitude } = position.coords;
          const advisoryData = await getLocalizedAdvisory(latitude, longitude, language);
          setLocalAdvisory(advisoryData.text);
          setLocalGrounding(advisoryData.urls);
        } catch (err) {
          console.error(err);
        } finally {
          setLocationLoading(false);
        }
      },
      (err) => {
        alert("Please enable location permissions to get weather-based advice.");
        setLocationLoading(false);
      }
    );
  };

  const saveToHistory = async (mode: AppMode, text: string) => {
    const newItem = {
      timestamp: Date.now(),
      mode: mode,
      result: text,
      previewText: text.substring(0, 100) + "..."
    };
    try {
      await addHistory(newItem);
    } catch (e) {
      console.error("Firebase History Error:", e);
    }
  };

  const handleCreateListing = async () => {
    if (!newListing.name || !newListing.price || !file) {
      alert("Please fill all fields and upload a photo.");
      return;
    }

    setIsScanning(true);
    const reader = new FileReader();
    reader.onloadend = async () => {
      const listingData = {
        name: newListing.name!,
        price: newListing.price!,
        category: newListing.category as any,
        image: reader.result as string,
        farmerName: 'Farmer Bharat'
      };

      try {
        await addListing(listingData);
        setIsScanning(false);
        setIsAddingListing(false);
        setNewListing({ category: 'Vegetable' });
        setFile(null);
      } catch (e) {
        alert("Failed to create listing. Please try again.");
        setIsScanning(false);
      }
    };
    reader.readAsDataURL(file);
  };

  const handleAnalyze = async () => {
    if (!activeMode) return;
    setIsScanning(true);
    try {
      let analysisText = "";
      if (activeMode.id === AppMode.MARKET_INSIGHTS) {
        const data = await getMarketInsights('current market rates', language);
        analysisText = data.text;
      } else {
        if (!file) throw new Error("Select a photo.");
        analysisText = await analyzeDiagnosticMedia(file, activeMode.id, language);
      }
      setResult(analysisText);
      await saveToHistory(activeMode.id, analysisText);
    } catch (err: any) {
      alert(err.message);
    } finally {
      setIsScanning(false);
    }
  };

  return (
    <div className="min-h-screen bg-agri-ivory flex flex-col font-sans">

      <header className="glass sticky top-0 z-50 border-b border-emerald-100">
        <div className="max-w-2xl mx-auto px-4 h-20 flex items-center justify-between">
          <div className="flex items-center space-x-2 cursor-pointer" onClick={() => { setActiveMode(null); setIsAddingListing(false); setResult(null); }}>
             <div className="w-10 h-10 bg-gradient-to-br from-emerald-500 to-teal-600 rounded-full flex items-center justify-center text-xl shadow-lg">🌾</div>
             <h1 className="text-xl font-bold text-emerald-900 leading-none tracking-tight">KrishiX</h1>
          </div>

          <div className="flex items-center space-x-2">
            <button 
              onClick={() => setShowLangPicker(true)}
              className="p-2.5 bg-white border border-emerald-100 rounded-2xl shadow-sm flex items-center gap-2 hover:bg-emerald-50 transition-all group"
            >
              <span className="text-lg group-hover:rotate-12 transition-transform">🌐</span>
              <span className="text-[10px] font-black uppercase tracking-widest text-emerald-900 hidden sm:block">{language.nativeName}</span>
            </button>

            <div className="bg-emerald-50 p-1 rounded-2xl flex border border-emerald-100 shadow-inner">
              <button 
                onClick={() => { setRole(UserRole.FARMER); setActiveMode(null); setIsAddingListing(false); setResult(null); }}
                className={`px-4 py-1.5 rounded-xl text-[10px] uppercase font-black transition-all ${role === UserRole.FARMER ? 'bg-emerald-900 text-white shadow-md' : 'text-emerald-800 opacity-60'}`}
              >
                Farmer
              </button>
              <button 
                onClick={() => { setRole(UserRole.CONSUMER); setActiveMode(null); setIsAddingListing(false); setResult(null); }}
                className={`px-4 py-1.5 rounded-xl text-[10px] uppercase font-black transition-all ${role === UserRole.CONSUMER ? 'bg-emerald-900 text-white shadow-md' : 'text-emerald-800 opacity-60'}`}
              >
                Consumer
              </button>
            </div>
          </div>
        </div>
      </header>

      <main className="flex-grow max-w-2xl mx-auto w-full p-4 py-6">

        {role === UserRole.FARMER && !activeMode && !isAddingListing && !result && (
          <div className="space-y-10 animate-fade-in">
            {/* Smart Farm Insight */}
            <section className="space-y-4">
              <div className="flex items-center justify-between px-2">
                <h2 className="text-lg font-bold text-emerald-900 flex items-center gap-2">
                  <span className="w-2 h-6 bg-teal-500 rounded-full"></span>
                  Smart Farm Insight
                </h2>
                <button 
                  onClick={handleFetchLocalAdvisory} 
                  disabled={locationLoading}
                  className="text-[10px] font-black uppercase tracking-widest text-emerald-600 bg-emerald-100 px-3 py-1 rounded-full active:scale-95 transition-all"
                >
                  {locationLoading ? "Fetching..." : "Refresh Advisory"}
                </button>
              </div>

              {localAdvisory ? (
                <div className="glass p-6 rounded-[2.5rem] border border-teal-100 bg-gradient-to-br from-teal-50/50 to-white shadow-xl shadow-teal-900/5 animate-scale-up">
                  <div className="flex items-center gap-4 mb-4">
                    <div className="w-12 h-12 bg-teal-100 rounded-2xl flex items-center justify-center text-2xl">🌦️</div>
                    <div>
                      <p className="text-[10px] uppercase font-black tracking-widest text-teal-600">Weather-Based Advice</p>
                      <p className="text-xs text-emerald-900 font-bold opacity-60">Personalized for your coordinates</p>
                    </div>
                  </div>
                  <div className="prose prose-sm prose-teal max-w-none text-emerald-900 leading-relaxed font-medium">
                    <ReactMarkdown>{localAdvisory}</ReactMarkdown>
                  </div>
                  {localGrounding.length > 0 && (
                    <div className="mt-4 pt-4 border-t border-teal-50 flex flex-wrap gap-2">
                       {localGrounding.map((g, idx) => (
                         <a key={idx} href={g.uri} target="_blank" rel="noopener noreferrer" className="text-[10px] font-bold text-teal-600 bg-teal-50 px-2 py-1 rounded-lg hover:underline">
                           🔗 {g.title}
                         </a>
                       ))}
                    </div>
                  )}
                </div>
              ) : (
                <div className="bg-white p-8 border border-emerald-100 rounded-[2.5rem] text-center space-y-4 shadow-sm">
                   <div className="text-4xl">🛰️</div>
                   <div>
                     <p className="text-sm font-bold text-emerald-900">Unlock Local Intelligence</p>
                     <p className="text-xs text-emerald-600">Get weather and crop advice for your exact location.</p>
                   </div>
                   <button 
                    onClick={handleFetchLocalAdvisory}
                    className="px-8 py-3 bg-emerald-900 text-white rounded-2xl font-bold text-sm shadow-lg active:scale-95 transition-all"
                   >
                     Sense My Location
                   </button>
                </div>
              )}
            </section>

            {/* Agri-Expert Help */}
            <section className="space-y-4">
              <div className="flex items-center justify-between px-2">
                <h2 className="text-lg font-bold text-emerald-900 flex items-center gap-2">
                  <span className="w-2 h-6 bg-emerald-500 rounded-full"></span>
                  Agri-Expert Help
                </h2>
                <span className="text-[10px] font-black uppercase tracking-widest text-emerald-400">AI Modules</span>
              </div>
              <div className="grid grid-cols-2 gap-4">
                {AI_MODES.map(m => <ModeCard key={m.id} mode={m} onClick={setActiveMode} />)}
              </div>
            </section>

            {/* Farmer's Stall */}
            <section className="space-y-4">
              <div className="flex items-center justify-between px-2">
                <h2 className="text-lg font-bold text-emerald-900 flex items-center gap-2">
                  <span className="w-2 h-6 bg-amber-500 rounded-full"></span>
                  Farmer's Stall
                </h2>
                <span className="text-[10px] font-black uppercase tracking-widest text-amber-500">Sell Direct</span>
              </div>
              <button 
                onClick={() => setIsAddingListing(true)}
                className="w-full p-8 bg-white border-3 border-dashed border-emerald-100 rounded-[3rem] flex flex-col items-center gap-4 group hover:border-emerald-500 hover:bg-emerald-50/30 transition-all shadow-sm"
              >
                <div className="w-20 h-20 bg-emerald-50 rounded-3xl flex items-center justify-center text-4xl group-hover:scale-110 transition-transform duration-500 shadow-inner">🏪</div>
                <div className="text-center">
                  <p className="font-bold text-emerald-900 text-lg">List Your Produce</p>
                  <p className="text-xs text-emerald-500 font-medium">Add dairy or vegetables to the global bazaar</p>
                </div>
              </button>
            </section>
          </div>
        )}

        {/* Other components (Consumer Interface, Forms, Results, etc) remain similar */}
        {role === UserRole.CONSUMER && (
          <div className="space-y-8 animate-fade-in">
             <div className="text-center py-6 space-y-2">
               <h2 className="text-4xl font-black text-emerald-900 tracking-tight">KrishiX Bazaar</h2>
               <p className="text-emerald-600 font-medium">Pure. Local. Direct from the hands that harvest.</p>
             </div>

             <div className="grid grid-cols-1 sm:grid-cols-2 gap-6 pb-20">
                {listings.length === 0 ? (
                  <div className="col-span-full py-24 text-center opacity-40">
                    <span className="text-7xl block mb-6">🧺</span>
                    <p className="text-xl font-bold italic text-emerald-900">The bazaar is waking up...</p>
                    <p className="text-sm">No items listed in your vicinity yet.</p>
                  </div>
                ) : (
                  listings.map(l => (
                    <div key={l.id} className="bg-white rounded-[2.5rem] overflow-hidden shadow-2xl shadow-emerald-900/5 border border-emerald-50 group hover:-translate-y-2 transition-all duration-300 flex flex-col">
                       <div className="h-56 w-full relative shrink-0 overflow-hidden">
                          <img src={l.image} className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-700" alt={l.name} />
                          <div className="absolute top-4 left-4 px-4 py-1.5 bg-white/90 backdrop-blur rounded-full text-[10px] font-black uppercase tracking-widest text-emerald-900 shadow-xl">
                            {l.category}
                          </div>
                       </div>
                       <div className="p-6 space-y-4 flex-grow flex flex-col justify-between">
                          <div className="flex justify-between items-start">
                             <div className="pr-4">
                               <h3 className="font-bold text-emerald-900 text-xl line-clamp-1">{l.name}</h3>
                               <p className="text-[10px] text-emerald-500 font-black uppercase tracking-widest">By {l.farmerName}</p>
                             </div>
                             <div className="text-2xl font-black text-emerald-900 shrink-0">₹{l.price}</div>
                          </div>
                          <button className="w-full py-4 bg-emerald-900 text-white rounded-2xl font-bold shadow-xl active:scale-95 transition-all mt-2 hover:bg-emerald-800">
                             Buy Now
                          </button>
                       </div>
                    </div>
                  ))
                )}
             </div>
          </div>
        )}

        {isAddingListing && (
          <div className="animate-slide-up space-y-6">
            <div className="flex items-center justify-between">
              <button onClick={() => { setIsAddingListing(false); setFile(null); }} className="p-3 text-emerald-800 bg-emerald-100 rounded-2xl hover:bg-emerald-200 transition-all">
                <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={3}><path strokeLinecap="round" strokeLinejoin="round" d="M15 19l-7-7 7-7" /></svg>
              </button>
              <h2 className="text-xl font-bold text-emerald-900">Create New Listing</h2>
              <div className="w-12"></div>
            </div>

            <div className="glass rounded-[3rem] p-8 space-y-6 shadow-2xl border-emerald-100">
               <div className="space-y-2">
                 <label className="text-[10px] font-black uppercase text-emerald-500 px-3 tracking-widest">Product Photo</label>
                 <FileUpload label="Snap Fresh Item" acceptedTypes="image/*" onFileSelect={setFile} />
               </div>

               <div className="space-y-5">
                  <input type="text" onChange={(e) => setNewListing({...newListing, name: e.target.value})} placeholder="Product Name" className="w-full p-5 bg-emerald-50/50 rounded-2xl outline-none focus:border-emerald-500 text-emerald-900 font-bold border border-emerald-100 transition-all" />
                  <div className="flex gap-4">
                    <input type="number" onChange={(e) => setNewListing({...newListing, price: e.target.value})} placeholder="Price (₹)" className="w-full p-5 bg-emerald-50/50 rounded-2xl outline-none border border-emerald-100 text-emerald-900 font-bold" />
                    <select onChange={(e) => setNewListing({...newListing, category: e.target.value as any})} className="w-full p-5 bg-emerald-50/50 rounded-2xl outline-none border border-emerald-100 text-emerald-900 font-bold">
                      <option value="Vegetable">Vegetable</option>
                      <option value="Dairy">Dairy</option>
                    </select>
                  </div>
               </div>
               <button onClick={handleCreateListing} className="w-full py-6 bg-emerald-900 text-white rounded-[2rem] font-bold text-lg shadow-2xl active:scale-95 transition-all mt-4 hover:bg-emerald-800">
                 Launch to Bazaar 🚀
               </button>
            </div>
          </div>
        )}

        {activeMode && !result && !isScanning && (
          <div className="animate-slide-up space-y-6">
            <div className="flex items-center justify-between">
              <button onClick={() => setActiveMode(null)} className="p-3 text-emerald-800 bg-emerald-100 rounded-2xl hover:bg-emerald-200 transition-all">
                <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={3}><path strokeLinecap="round" strokeLinejoin="round" d="M15 19l-7-7 7-7" /></svg>
              </button>
              <h2 className="text-xl font-bold text-emerald-900">{activeMode.title}</h2>
              <div className="w-12"></div>
            </div>
            <div className="glass rounded-[3rem] p-10 space-y-8 shadow-2xl border-emerald-100">
              <FileUpload label={activeMode.inputLabel || "Upload Image"} acceptedTypes={activeMode.acceptedFileTypes || "*"} onFileSelect={setFile} />
              <button onClick={handleAnalyze} className="w-full py-6 bg-emerald-900 text-white rounded-[2rem] font-bold text-lg shadow-xl active:scale-95 transition-all hover:bg-emerald-800">
                Run AI Diagnostic
              </button>
            </div>
          </div>
        )}

        {result && (
          <div className="animate-fade-in space-y-6">
             <div className="flex items-center justify-between">
                <button onClick={() => {setResult(null); setActiveMode(null);}} className="p-3 bg-emerald-100 rounded-2xl text-emerald-800 hover:bg-emerald-200 transition-all">
                   <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={3}><path strokeLinecap="round" strokeLinejoin="round" d="M15 19l-7-7 7-7" /></svg>
                </button>
                <h2 className="text-xl font-bold text-emerald-900">Diagnosis Report</h2>
                <div className="w-12"></div>
             </div>
             <div className="glass p-8 rounded-[3rem] shadow-2xl space-y-8 border border-emerald-100 bg-white">
                <div className="prose prose-emerald prose-sm max-w-none text-emerald-900 font-medium leading-relaxed">
                   <ReactMarkdown>{result}</ReactMarkdown>
                </div>
                <button 
                  onClick={async () => {
                    const audio = await generateSpeech(result, language);
                    if (audio) playPCM(audio);
                  }}
                  className="w-full py-5 bg-emerald-900 text-white rounded-2xl font-bold flex items-center justify-center gap-4 shadow-xl hover:bg-emerald-800 transition-all active:scale-95"
                >
                  <span className="text-2xl">🔊</span> 
                  <span>Read Report Aloud</span>
                </button>
             </div>
          </div>
        )}
      </main>

      <div className="fixed bottom-8 right-8 flex flex-col gap-5 z-40">
        <button 
          onClick={() => setShowHistory(true)}
          className="w-16 h-16 bg-white border-2 border-emerald-50 text-emerald-900 rounded-[1.5rem] shadow-2xl flex items-center justify-center transform hover:scale-110 active:scale-95 transition-all group"
        >
          <svg className="w-7 h-7 group-hover:rotate-12 transition-transform" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2.5}>
            <path strokeLinecap="round" strokeLinejoin="round" d="M12 6v6h4.5m4.5 0a9 9 0 11-18 0 9 9 0 0118 0z" />
          </svg>
        </button>
        <button 
          onClick={() => setShowChat(true)}
          className="w-20 h-20 bg-gradient-to-br from-emerald-500 to-teal-600 text-white rounded-[2rem] shadow-[0_20px_50px_rgba(16,185,129,0.3)] flex items-center justify-center transform hover:scale-110 active:scale-95 transition-all relative group"
        >
          <span className="text-4xl group-hover:bounce">🤖</span>
        </button>
      </div>

      <ChatInterface isOpen={showChat} onClose={() => setShowChat(false)} currentLanguage={language} />
      <HistoryModal isOpen={showHistory} onClose={() => setShowHistory(false)} history={history} onSelect={(i) => {setResult(i.result); setShowHistory(false);}} onShare={() => {}} onClear={() => {}} />
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import ReactMarkdown from 'react-markdown';
import { AppMode, ModeConfig, HistoryItem, Language, SUPPORTED_LANGUAGES, UserRole, Listing } from './types';
import { ModeCard } from './components/ModeCard';
import { FileUpload } from './components/FileUpload';
import { ChatInterface } from './components/ChatInterface';
import { HistoryModal } from './components/HistoryModal';
import { 
  analyzeDiagnosticMedia, 
  getDailyTip, 
  generateSpeech,
  getMarketInsights,
  getLocalizedAdvisory,
  playPCM
} from './services/geminiService';
import { db, addListing, addHistory, LISTINGS_COLLECTION, HISTORY_COLLECTION } from './services/firebaseService';
import { collection, query, orderBy, onSnapshot, limit } from 'firebase/firestore';

const AI_MODES: ModeConfig[] = [
  {
    id: AppMode.CROP_DOCTOR,
    title: 'Crop Doctor',
    description: 'Pathology & nutrient scanning.',
    icon: '🌱',
    acceptedFileTypes: 'image/*',
    inputLabel: 'Scan Leaf',
  },
  {
    id: AppMode.VET_DERM,
    title: 'Derm-Scan',
    description: 'Livestock skin diagnostics.',
    icon: '🐄',
    acceptedFileTypes: 'image/*',
    inputLabel: 'Diagnostic Photo',
  },
  {
    id: AppMode.ANIMAL_BEHAVIOR,
    title: 'Animal Pulse',
    description: 'Stress & pain detection.',
    icon: '🐕',
    acceptedFileTypes: 'video/*,image/gif',
    inputLabel: 'Analysis',
  },
  {
    id: AppMode.MARKET_INSIGHTS,
    title: 'Market Intelligence',
    description: 'Prices & local news.',
    icon: '📈',
    inputLabel: '',
    acceptedFileTypes: ''
  }
];

const App: React.FC = () => {
  const [role, setRole] = useState<UserRole>(UserRole.FARMER);
  const [activeMode, setActiveMode] = useState<ModeConfig | null>(null);
  const [isScanning, setIsScanning] = useState(false);
  const [result, setResult] = useState<string | null>(null);
  const [language, setLanguage] = useState<Language>(SUPPORTED_LANGUAGES[0]);
  const [showLangPicker, setShowLangPicker] = useState(false);
  const [dailyTip, setDailyTip] = useState<string>('Welcome to KrishiX...');

  // Localized Advisory States
  const [localAdvisory, setLocalAdvisory] = useState<string | null>(null);
  const [localGrounding, setLocalGrounding] = useState<any[]>([]);
  const [locationLoading, setLocationLoading] = useState(false);

  const [showChat, setShowChat] = useState(false);
  const [history, setHistory] = useState<HistoryItem[]>([]);
  const [showHistory, setShowHistory] = useState(false);

  // Marketplace States
  const [listings, setListings] = useState<Listing[]>([]);
  const [isAddingListing, setIsAddingListing] = useState(false);
  const [newListing, setNewListing] = useState<Partial<Listing>>({ category: 'Vegetable' });
  const [file, setFile] = useState<File | null>(null);
  const [previewUrl, setPreviewUrl] = useState<string | null>(null);

  useEffect(() => {
    getDailyTip(language).then(setDailyTip);

    const listingsQuery = query(collection(db, LISTINGS_COLLECTION), orderBy("createdAt", "desc"));
    const unsubscribeListings = onSnapshot(listingsQuery, (snapshot) => {
      const data = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() })) as Listing[];
      setListings(data);
    });

    const historyQuery = query(collection(db, HISTORY_COLLECTION), orderBy("timestamp", "desc"), limit(20));
    const unsubscribeHistory = onSnapshot(historyQuery, (snapshot) => {
      const data = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() })) as HistoryItem[];
      setHistory(data);
    });

    return () => {
      unsubscribeListings();
      unsubscribeHistory();
    };
  }, [language]);

  const handleFetchLocalAdvisory = () => {
    setLocationLoading(true);
    if (!navigator.geolocation) {
      alert("Geolocation is not supported by your browser");
      setLocationLoading(false);
      return;
    }

    navigator.geolocation.getCurrentPosition(
      async (position) => {
        try {
          const { latitude, longitude } = position.coords;
          const advisoryData = await getLocalizedAdvisory(latitude, longitude, language);
          setLocalAdvisory(advisoryData.text);
          setLocalGrounding(advisoryData.urls);
        } catch (err) {
          console.error(err);
        } finally {
          setLocationLoading(false);
        }
      },
      (err) => {
        alert("Please enable location permissions to get weather-based advice.");
        setLocationLoading(false);
      }
    );
  };

  const saveToHistory = async (mode: AppMode, text: string) => {
    const newItem = {
      timestamp: Date.now(),
      mode: mode,
      result: text,
      previewText: text.substring(0, 100) + "..."
    };
    try {
      await addHistory(newItem);
    } catch (e) {
      console.error("Firebase History Error:", e);
    }
  };

  const handleFileSelect = (f: File) => {
    setFile(f);
    const url = URL.createObjectURL(f);
    setPreviewUrl(url);
  };

  const handleCreateListing = async () => {
    if (!newListing.name || !newListing.price || !file) {
      alert("Please fill all fields and upload a photo.");
      return;
    }

    setIsScanning(true);
    const reader = new FileReader();
    reader.onloadend = async () => {
      const listingData = {
        name: newListing.name!,
        price: newListing.price!,
        category: newListing.category as any,
        image: reader.result as string,
        farmerName: 'Farmer Bharat'
      };

      try {
        await addListing(listingData);
        setIsScanning(false);
        setIsAddingListing(false);
        setNewListing({ category: 'Vegetable' });
        setFile(null);
        setPreviewUrl(null);
      } catch (e) {
        alert("Failed to create listing. Please try again.");
        setIsScanning(false);
      }
    };
    reader.readAsDataURL(file);
  };

  const handleAnalyze = async () => {
    if (!activeMode) return;
    setIsScanning(true);
    try {
      let analysisText = "";
      if (activeMode.id === AppMode.MARKET_INSIGHTS) {
        const data = await getMarketInsights('current market rates', language);
        analysisText = data.text;
      } else {
        if (!file) throw new Error("Select a photo.");
        analysisText = await analyzeDiagnosticMedia(file, activeMode.id, language);
      }
      setResult(analysisText);
      await saveToHistory(activeMode.id, analysisText);
    } catch (err: any) {
      alert(err.message);
    } finally {
      setIsScanning(false);
    }
  };

  const shareReport = () => {
