                    <div key={l.id} className="bg-white rounded-[2.5rem] overflow-hidden shadow-2xl shadow-emerald-900/5 border border-emerald-50 group hover:-translate-y-2 transition-all duration-300 flex flex-col">
                       <div className="h-56 w-full relative shrink-0 overflow-hidden">
                          <img src={l.image} className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-700" alt={l.name} />
                          <div className="absolute top-4 left-4 px-4 py-1.5 bg-white/90 backdrop-blur rounded-full text-[10px] font-black uppercase tracking-widest text-emerald-900 shadow-xl">
                            {l.category}
                          </div>
                       </div>
                       <div className="p-6 space-y-4 flex-grow flex flex-col justify-between">
                          <div className="flex justify-between items-start">
                             <div className="pr-4">
                               <h3 className="font-bold text-emerald-900 text-xl line-clamp-1">{l.name}</h3>
                               <p className="text-[10px] text-emerald-500 font-black uppercase tracking-widest">By {l.farmerName}</p>
                             </div>
                             <div className="text-2xl font-black text-emerald-900 shrink-0">₹{l.price}</div>
                          </div>
                          <button 
                            onClick={() => handleBuyNow(l)}
                            className="w-full py-4 bg-emerald-900 text-white rounded-2xl font-bold shadow-xl active:scale-95 transition-all mt-2 hover:bg-emerald-800"
                          >
                             Buy Now
                          </button>
                       </div>
                    </div>
                  ))
                )}
             </div>
          </div>
        )}

        {isAddingListing && (
          <div className="animate-slide-up space-y-6">
            <div className="flex items-center justify-between">
              <button onClick={() => { setIsAddingListing(false); setFile(null); setPreviewUrl(null); }} className="p-3 text-emerald-800 bg-emerald-100 rounded-2xl hover:bg-emerald-200 transition-all">
                <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={3}><path strokeLinecap="round" strokeLinejoin="round" d="M15 19l-7-7 7-7" /></svg>
              </button>
              <h2 className="text-xl font-bold text-emerald-900">Create New Listing</h2>
              <div className="w-12"></div>
            </div>

            <div className="glass rounded-[3rem] p-8 space-y-6 shadow-2xl border-emerald-100">
               <div className="space-y-2">
                 <label className="text-[10px] font-black uppercase text-emerald-500 px-3 tracking-widest">Product Photo</label>
                 <FileUpload label="Snap Fresh Item" acceptedTypes="image/*" onFileSelect={handleFileSelect} />
               </div>

               <div className="space-y-5">
                  <input type="text" onChange={(e) => setNewListing({...newListing, name: e.target.value})} placeholder="Product Name" className="w-full p-5 bg-emerald-50/50 rounded-2xl outline-none focus:border-emerald-500 text-emerald-900 font-bold border border-emerald-100 transition-all" />
                  <div className="flex gap-4">
                    <input type="number" onChange={(e) => setNewListing({...newListing, price: e.target.value})} placeholder="Price (₹)" className="w-full p-5 bg-emerald-50/50 rounded-2xl outline-none border border-emerald-100 text-emerald-900 font-bold" />
                    <select onChange={(e) => setNewListing({...newListing, category: e.target.value as any})} className="w-full p-5 bg-emerald-50/50 rounded-2xl outline-none border border-emerald-100 text-emerald-900 font-bold">
                      <option value="Vegetable">Vegetable</option>
                      <option value="Dairy">Dairy</option>
                    </select>
                  </div>
               </div>
               <button onClick={handleCreateListing} className="w-full py-6 bg-emerald-900 text-white rounded-[2rem] font-bold text-lg shadow-2xl active:scale-95 transition-all mt-4 hover:bg-emerald-800">
                 Launch to Bazaar 🚀
               </button>
            </div>
          </div>
        )}

        {activeMode && !result && !isScanning && (
          <div className="animate-slide-up space-y-6">
            <div className="flex items-center justify-between">
              <button onClick={() => { setActiveMode(null); setFile(null); setPreviewUrl(null); }} className="p-3 text-emerald-800 bg-emerald-100 rounded-2xl hover:bg-emerald-200 transition-all">
                <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={3}><path strokeLinecap="round" strokeLinejoin="round" d="M15 19l-7-7 7-7" /></svg>
              </button>
              <h2 className="text-xl font-bold text-emerald-900">{activeMode.title}</h2>
              <div className="w-12"></div>
            </div>
            <div className="glass rounded-[3rem] p-10 space-y-8 shadow-2xl border-emerald-100">
              <FileUpload label={activeMode.inputLabel || "Upload Image"} acceptedTypes={activeMode.acceptedFileTypes || "*"} onFileSelect={handleFileSelect} />
              <button onClick={handleAnalyze} className="w-full py-6 bg-emerald-900 text-white rounded-[2rem] font-bold text-lg shadow-xl active:scale-95 transition-all hover:bg-emerald-800">
                Run AI Diagnostic
              </button>
            </div>
          </div>
        )}

        {result && (
          <div className="animate-fade-in space-y-8 pb-12">
             <div className="flex items-center justify-between">
                <button onClick={() => {setResult(null); setActiveMode(null); setFile(null); setPreviewUrl(null);}} className="p-3 bg-emerald-100 rounded-2xl text-emerald-800 hover:bg-emerald-200 transition-all">
                   <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={3}><path strokeLinecap="round" strokeLinejoin="round" d="M15 19l-7-7 7-7" /></svg>
                </button>
                <h2 className="text-xl font-black text-emerald-900 tracking-tight">AI Health Certificate</h2>
                <button onClick={shareReport} className="p-3 bg-emerald-900 text-white rounded-2xl hover:bg-emerald-800 transition-all shadow-lg active:scale-90">
                   <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2.5}><path strokeLinecap="round" strokeLinejoin="round" d="M8.684 13.342C8.886 12.938 9 12.482 9 12c0-.482-.114-.938-.316-1.342m0 2.684a3 3 0 110-2.684m0 2.684l6.632 3.316m-6.632-6l6.632-3.316m0 0a3 3 0 105.367-2.684 3 3 0 00-5.367 2.684zm0 9.316a3 3 0 105.368 2.684 3 3 0 00-5.368-2.684z" /></svg>
                </button>
             </div>

             <div className="space-y-6">
                {/* Evidence Thumbnail & Diagnosis Header */}
                <div className="bg-white rounded-[2.5rem] p-6 shadow-2xl border border-emerald-100 flex gap-6 items-center">
                   {previewUrl && (
                     <div className="w-24 h-24 rounded-2xl overflow-hidden border-2 border-emerald-50 shrink-0 shadow-inner">
                        <img src={previewUrl} className="w-full h-full object-cover" alt="Scan Evidence" />
                     </div>
                   )}
                   <div className="flex-1 space-y-2">
                      <div className="flex items-center gap-2">
                         <span className={`px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-widest ${result.toLowerCase().includes('critical') || result.toLowerCase().includes('high') ? 'bg-red-100 text-red-600' : 'bg-emerald-100 text-emerald-600'}`}>
                           {result.toLowerCase().includes('critical') ? 'Status: Alert' : 'Status: analyzed'}
                         </span>
                         <span className="text-[10px] text-emerald-400 font-bold">{new Date().toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}</span>
                      </div>
                      <p className="text-lg font-black text-emerald-900 leading-tight">Diagnostic Verified by KrishiX AI</p>
                   </div>
                </div>

                {/* Structured Insights Cards */}
                <div className="grid gap-6">
                   <div className="glass p-8 rounded-[3rem] shadow-xl border border-emerald-50 bg-white/50">
                      <div className="prose prose-emerald prose-sm max-w-none 
                        prose-headings:text-emerald-900 prose-headings:font-black prose-headings:mt-8 prose-headings:mb-4
                        prose-p:text-emerald-800 prose-p:font-medium prose-p:leading-relaxed
                        prose-li:text-emerald-800 prose-li:font-medium prose-strong:text-emerald-900 prose-strong:font-black">
                         <ReactMarkdown 
                            components={{
                               h2: ({node, ...props}) => (
                                 <div className="flex items-center gap-3 mt-8 mb-4">
                                   <div className="w-2 h-6 bg-emerald-500 rounded-full"></div>
                                   <h2 {...props} className="text-xl font-black text-emerald-900 m-0" />
                                 </div>
                               ),
                               h1: ({node, ...props}) => (
                                 <h1 {...props} className="text-2xl font-black text-emerald-900 mb-6" />
                               )
                            }}
                         >
                           {result}
                         </ReactMarkdown>
                      </div>
                   </div>
                </div>

                {/* Final Actions */}
                <div className="grid grid-cols-2 gap-4">
                   <button 
                      onClick={async () => {
                        const audio = await generateSpeech(result, language);
                        if (audio) playPCM(audio);
                      }}
                      className="py-5 bg-emerald-900 text-white rounded-2xl font-bold flex items-center justify-center gap-3 shadow-xl hover:bg-emerald-800 transition-all active:scale-95 group"
                   >
                      <span className="text-xl group-hover:scale-125 transition-transform">🔊</span> 
                      <span>Read Report</span>
                   </button>
                   <button 
                      onClick={shareReport}
                      className="py-5 bg-white border-2 border-emerald-900 text-emerald-900 rounded-2xl font-bold flex items-center justify-center gap-3 shadow-xl hover:bg-emerald-50 transition-all active:scale-95 group"
                   >
                      <span className="text-xl">💬</span> 
                      <span>WhatsApp</span>
                   </button>
                </div>
             </div>
          </div>
        )}
      </main>

      {/* Picker Modal */}
      {showLangPicker && (
        <div className="fixed inset-0 z-[100] bg-emerald-950/80 backdrop-blur-md flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-lg rounded-[3rem] shadow-2xl p-8 animate-scale-up border border-white/20">
            <div className="flex justify-between items-center mb-8">
              <h2 className="text-2xl font-black text-emerald-900">Choose Language</h2>
              <button onClick={() => setShowLangPicker(false)} className="p-2 text-emerald-400 hover:text-emerald-900">
                <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={3}><path strokeLinecap="round" strokeLinejoin="round" d="M6 18L18 6M6 6l12 12" /></svg>
              </button>
            </div>
            <div className="grid grid-cols-2 sm:grid-cols-3 gap-4">
              {SUPPORTED_LANGUAGES.map((lang) => (
                <button
                  key={lang.code}
                  onClick={() => {
                    setLanguage(lang);
                    setShowLangPicker(false);
                  }}
                  className={`p-4 rounded-2xl text-center border-2 transition-all group ${
                    language.code === lang.code 
                    ? 'border-emerald-500 bg-emerald-50 shadow-inner' 
                    : 'border-emerald-50 bg-white hover:border-emerald-200'
                  }`}
                >
                  <p className="text-xl font-black text-emerald-900 mb-1 group-hover:scale-110 transition-transform">{lang.nativeName}</p>
                  <p className="text-[10px] text-emerald-400 font-bold uppercase tracking-widest">{lang.name}</p>
                </button>
              ))}
            </div>
          </div>
        </div>
      )}

      {isScanning && (
        <div className="fixed inset-0 z-[100] bg-emerald-950/95 flex flex-col items-center justify-center p-8 backdrop-blur-sm">
           <div className="w-72 h-72 border-4 border-emerald-400/20 rounded-full flex items-center justify-center animate-pulse mb-10 relative">
              <div className="absolute inset-0 rounded-full border-t-4 border-emerald-400 animate-spin"></div>
              <span className="text-8xl filter drop-shadow-[0_0_15px_rgba(16,185,129,0.5)]">🧬</span>
              <div className="absolute inset-x-0 top-1/2 scan-line bg-gradient-to-r from-transparent via-emerald-400 to-transparent h-1.5 w-full shadow-[0_0_20px_#10b981]"></div>
           </div>
           <p className="text-white text-3xl font-black mb-2 tracking-tight">KrishiX Intelligence</p>
           <p className="text-emerald-400 font-bold uppercase tracking-[0.3em] text-xs animate-pulse">Running Neural Diagnostics...</p>
        </div>
      )}

      <div className="fixed bottom-8 right-8 flex flex-col gap-5 z-40">
        <button 
          onClick={() => setShowHistory(true)}
          className="w-16 h-16 bg-white border-2 border-emerald-50 text-emerald-900 rounded-[1.5rem] shadow-2xl flex items-center justify-center transform hover:scale-110 active:scale-95 transition-all group"
        >
          <svg className="w-7 h-7 group-hover:rotate-12 transition-transform" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2.5}>
            <path strokeLinecap="round" strokeLinejoin="round" d="M12 6v6h4.5m4.5 0a9 9 0 11-18 0 9 9 0 0118 0z" />
          </svg>
        </button>
        <button 
          onClick={() => setShowChat(true)}
          className="w-20 h-20 bg-gradient-to-br from-emerald-500 to-teal-600 text-white rounded-[2rem] shadow-[0_20px_50px_rgba(16,185,129,0.3)] flex items-center justify-center transform hover:scale-110 active:scale-95 transition-all relative group"
        >
          <span className="text-4xl group-hover:bounce">🤖</span>
        </button>
      </div>

      <ChatInterface isOpen={showChat} onClose={() => setShowChat(false)} currentLanguage={language} />
      <HistoryModal isOpen={showHistory} onClose={() => setShowHistory(false)} history={history} onSelect={(i) => {setResult(i.result); setShowHistory(false);}} onShare={() => {}} onClear={() => {}} />
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import ReactMarkdown from 'react-markdown';
import { AppMode, ModeConfig, HistoryItem, Language, SUPPORTED_LANGUAGES, UserRole, Listing } from './types';
import { ModeCard } from './components/ModeCard';
import { FileUpload } from './components/FileUpload';
import { ChatInterface } from './components/ChatInterface';
import { HistoryModal } from './components/HistoryModal';
import { 
  analyzeDiagnosticMedia, 
  getDailyTip, 
  generateSpeech,
  getMarketInsights,
  getLocalizedAdvisory,
  playPCM
} from './services/geminiService';
import { db, addListing, addHistory, LISTINGS_COLLECTION, HISTORY_COLLECTION } from './services/firebaseService';
import { collection, query, orderBy, onSnapshot, limit } from 'firebase/firestore';

const AI_MODES: ModeConfig[] = [
  {
    id: AppMode.CROP_DOCTOR,
    title: 'Crop Doctor',
    description: 'Pathology & nutrient scanning.',
    icon: '🌱',
    acceptedFileTypes: 'image/*',
    inputLabel: 'Scan Leaf',
  },
  {
    id: AppMode.VET_DERM,
    title: 'Derm-Scan',
    description: 'Livestock skin diagnostics.',
    icon: '🐄',
    acceptedFileTypes: 'image/*',
    inputLabel: 'Diagnostic Photo',
  },
  {
    id: AppMode.ANIMAL_BEHAVIOR,
    title: 'Animal Pulse',
    description: 'Stress & pain detection.',
    icon: '🐕',
    acceptedFileTypes: 'video/*,image/gif',
    inputLabel: 'Analysis',
  },
  {
    id: AppMode.MARKET_INSIGHTS,
    title: 'Market Intelligence',
    description: 'Prices & local news.',
    icon: '📈',
    inputLabel: '',
    acceptedFileTypes: ''
  }
];

type TabType = 'home' | 'diagnostics' | 'stall' | 'history' | 'shop' | 'chat';

const App: React.FC = () => {
  const [role, setRole] = useState<UserRole>(UserRole.FARMER);
  const [isRoleSelected, setIsRoleSelected] = useState(false);
  const [activeTab, setActiveTab] = useState<TabType>('home');
  const [activeMode, setActiveMode] = useState<ModeConfig | null>(null);
  const [isScanning, setIsScanning] = useState(false);
  const [result, setResult] = useState<string | null>(null);
  const [language, setLanguage] = useState<Language>(SUPPORTED_LANGUAGES[0]);
  const [showLangPicker, setShowLangPicker] = useState(false);
  const [dailyTip, setDailyTip] = useState<string>('Welcome to KrishiX...');
  const [paymentSuccess, setPaymentSuccess] = useState<string | null>(null);

  // Localized Advisory States
  const [localAdvisory, setLocalAdvisory] = useState<string | null>(null);
  const [localGrounding, setLocalGrounding] = useState<any[]>([]);
  const [locationLoading, setLocationLoading] = useState(false);

  const [showChat, setShowChat] = useState(false);
  const [history, setHistory] = useState<HistoryItem[]>([]);
  const [showHistory, setShowHistory] = useState(false);

  // Marketplace States
  const [listings, setListings] = useState<Listing[]>([]);
  const [isAddingListing, setIsAddingListing] = useState(false);
  const [newListing, setNewListing] = useState<Partial<Listing>>({ category: 'Vegetable' });
  const [file, setFile] = useState<File | null>(null);
  const [previewUrl, setPreviewUrl] = useState<string | null>(null);

  useEffect(() => {
    getDailyTip(language).then(setDailyTip);

    const listingsQuery = query(collection(db, LISTINGS_COLLECTION), orderBy("createdAt", "desc"));
    const unsubscribeListings = onSnapshot(listingsQuery, (snapshot) => {
      const data = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() })) as Listing[];
      setListings(data);
    });

    const historyQuery = query(collection(db, HISTORY_COLLECTION), orderBy("timestamp", "desc"), limit(20));
    const unsubscribeHistory = onSnapshot(historyQuery, (snapshot) => {
      const data = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() })) as HistoryItem[];
      setHistory(data);
    });

    return () => {
      unsubscribeListings();
      unsubscribeHistory();
    };
  }, [language]);

  const handleFetchLocalAdvisory = () => {
    setLocationLoading(true);
    if (!navigator.geolocation) {
      alert("Geolocation is not supported by your browser");
      setLocationLoading(false);
      return;
    }

    navigator.geolocation.getCurrentPosition(
      async (position) => {
        try {
          const { latitude, longitude } = position.coords;
          const advisoryData = await getLocalizedAdvisory(latitude, longitude, language);
          setLocalAdvisory(advisoryData.text);
          setLocalGrounding(advisoryData.urls);
        } catch (err) {
          console.error(err);
        } finally {
          setLocationLoading(false);
        }
      },
      (err) => {
        alert("Please enable location permissions to get weather-based advice.");
        setLocationLoading(false);
      }
    );
  };

  const saveToHistory = async (mode: AppMode, text: string) => {
    const newItem = {
      timestamp: Date.now(),
      mode: mode,
      result: text,
      previewText: text.substring(0, 100) + "..."
    };
    try {
      await addHistory(newItem);
    } catch (e) {
      console.error("Firebase History Error:", e);
    }
  };

  const handleFileSelect = (f: File) => {
    setFile(f);
    const url = URL.createObjectURL(f);
    setPreviewUrl(url);
  };

  const handleCreateListing = async () => {
    if (!newListing.name || !newListing.price || !file) {
      alert("Please fill all fields and upload a photo.");
      return;
    }

    setIsScanning(true);
    const reader = new FileReader();
    reader.onloadend = async () => {
      const listingData = {
        name: newListing.name!,
        price: newListing.price!,
        category: newListing.category as any,
        image: reader.result as string,
        farmerName: 'Farmer Bharat'
      };

      try {
        await addListing(listingData);
        setIsScanning(false);
        setIsAddingListing(false);
        setActiveTab('stall');
        setNewListing({ category: 'Vegetable' });
        setFile(null);
        setPreviewUrl(null);
      } catch (e) {
        alert("Failed to create listing. Please try again.");
        setIsScanning(false);
      }
    };
    reader.readAsDataURL(file);
  };

  const handleAnalyze = async () => {
    if (!activeMode) return;
    setIsScanning(true);
    try {
      let analysisText = "";
      if (activeMode.id === AppMode.MARKET_INSIGHTS) {
        const data = await getMarketInsights('current market rates', language);
        analysisText = data.text;
      } else {
        if (!file) throw new Error("Select a photo.");
        analysisText = await analyzeDiagnosticMedia(file, activeMode.id, language);
      }
      setResult(analysisText);
      await saveToHistory(activeMode.id, analysisText);
    } catch (err: any) {
      alert(err.message);
    } finally {
      setIsScanning(false);
    }
  };

  const handleBuyNow = (listing: Listing) => {
    const options = {
      key: "rzp_test_R63nysub7CBtrS",
      amount: parseInt(listing.price) * 100, // Amount in paise
      currency: "INR",
      name: "KrishiX Bazaar",
      description: `Direct purchase of ${listing.name}`,
      image: "https://cdn-icons-png.flaticon.com/512/2103/2103525.png",
      handler: function (response: any) {
        setPaymentSuccess(`Order Placed Successfully! ID: ${response.razorpay_payment_id}`);
        setTimeout(() => setPaymentSuccess(null), 5000);
      },
      prefill: {
        name: "Farmer Bharat",
        email: "bharat@krishix.ai",
        contact: "9999999999"
      },
      theme: {
        color: "#064e3b"
      }
    };

    const rzp = new (window as any).Razorpay(options);
    rzp.open();
  };

  const shareReport = () => {
    if (!result) return;
    const shareText = `*KrishiX AI Diagnostic Report*\n\n${result.substring(0, 500)}...\n\nGenerated by KrishiX AI.`;
    const whatsappUrl = `https://wa.me/?text=${encodeURIComponent(shareText)}`;
    window.open(whatsappUrl, '_blank');
  };

  const selectRole = (selectedRole: UserRole) => {
    setRole(selectedRole);
    setIsRoleSelected(true);
    setActiveTab(selectedRole === UserRole.FARMER ? 'home' : 'shop');
  };

  // Nav Button Component for Reuse
  const NavButton = ({ tab, icon, label }: { tab: TabType, icon: string, label: string }) => {
    const isActive = activeTab === tab;
    return (
      <button 
        onClick={() => {
          setActiveTab(tab);
          setResult(null);
          setActiveMode(null);
          setIsAddingListing(false);
        }}
        className={`flex flex-col items-center justify-center flex-1 py-3 transition-all relative ${isActive ? 'text-emerald-900' : 'text-emerald-400 opacity-60'}`}
      >
        <div className={`text-2xl transition-transform duration-300 ${isActive ? 'scale-110 -translate-y-1' : ''}`}>{icon}</div>
        <span className={`text-[10px] font-black uppercase tracking-widest mt-1 ${isActive ? 'opacity-100' : 'opacity-0 h-0 overflow-hidden'}`}>{label}</span>
        {isActive && <div className="absolute bottom-1 w-1 h-1 bg-emerald-900 rounded-full animate-pulse"></div>}
      </button>
    );
  };

  if (!isRoleSelected) {
    return (
      <div className="min-h-screen bg-agri-ivory flex flex-col items-center justify-center p-6 bg-gradient-to-br from-emerald-50 via-white to-teal-50">
        <div className="max-w-md w-full text-center space-y-12 animate-fade-in">
          <div className="space-y-4">
            <div className="w-24 h-24 bg-gradient-to-br from-emerald-500 to-teal-600 rounded-[2rem] flex items-center justify-center text-5xl shadow-2xl mx-auto transform hover:rotate-12 transition-transform duration-500">
              🌾
            </div>
            <h1 className="text-5xl font-black text-emerald-900 tracking-tighter">KrishiX</h1>
            <p className="text-emerald-600 font-bold uppercase tracking-[0.3em] text-[10px]">Precision AI Agriculture</p>
          </div>

          <div className="space-y-6">
            <p className="text-emerald-900 font-bold text-lg">Welcome! How would you like to use KrishiX today?</p>

            <div className="grid grid-cols-1 gap-5">
              <button 
                onClick={() => selectRole(UserRole.FARMER)}
                className="group relative bg-white border-2 border-emerald-100 p-8 rounded-[2.5rem] text-left hover:border-emerald-500 hover:shadow-2xl hover:shadow-emerald-900/10 transition-all duration-300 active:scale-95 overflow-hidden"
              >
                <div className="absolute top-0 right-0 w-32 h-32 bg-emerald-50 rounded-full -mr-12 -mt-12 group-hover:scale-110 transition-transform duration-500"></div>
                <div className="relative flex items-center gap-6">
