    navigator.geolocation.getCurrentPosition(
      async (position) => {
        try {
          const { latitude, longitude } = position.coords;
          const advisoryData = await getLocalizedAdvisory(latitude, longitude, language);
          setLocalAdvisory(advisoryData.text);
          setLocalGrounding(advisoryData.urls);
        } catch (err) {
          console.error(err);
        } finally {
          setLocationLoading(false);
        }
      },
      (err) => {
        alert("Please enable location permissions to get weather-based advice.");
        setLocationLoading(false);
      }
    );
  };

