                   <button onClick={handleHome} className="py-5 bg-white border-2 border-emerald-900 text-emerald-900 rounded-2xl font-bold flex items-center justify-center gap-3 shadow-xl active:scale-95"><span>🏠</span> <span>Home</span></button>
                </div>
             </div>
          </div>
        )}
      </main>

      {/* Fixed Bottom Navigation */}
      <nav className="fixed bottom-0 left-0 right-0 z-50 glass border-t border-emerald-100 rounded-t-[2.5rem] shadow-[0_-10px_30px_rgba(0,0,0,0.05)] px-4">
        <div className="max-w-2xl mx-auto flex h-20 items-center justify-around">
          {role === UserRole.FARMER ? (
            <>
              <NavButton tab="home" icon="🛰️" label="Insights" />
              <NavButton tab="diagnostics" icon="🩺" label="AI Scan" />
              <NavButton tab="stall" icon="🏪" label="Sell" />
              <NavButton tab="history" icon="📜" label="Archive" />
            </>
          ) : (
            <>
              <NavButton tab="shop" icon="🛍️" label="Shop" />
              <button onClick={() => setShowChat(true)} className="flex flex-col items-center justify-center flex-1 text-emerald-400 opacity-60">
                 <div className="text-2xl">🤖</div>
                 <span className="text-[10px] font-black uppercase tracking-widest mt-1">Concierge</span>
              </button>
            </>
          )}
        </div>
      </nav>

      {/* Modals & Screens */}
      {showLangPicker && (
        <div className="fixed inset-0 z-[100] bg-emerald-950/80 backdrop-blur-md flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-lg rounded-[3rem] shadow-2xl p-8 animate-scale-up border border-white/20">
            <div className="flex justify-between items-center mb-8">
              <h2 className="text-2xl font-black text-emerald-900">Choose Language</h2>
              <button onClick={() => setShowLangPicker(false)} className="p-2 text-emerald-400 hover:text-emerald-900"><svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={3}><path strokeLinecap="round" strokeLinejoin="round" d="M6 18L18 6M6 6l12 12" /></svg></button>
            </div>
            <div className="grid grid-cols-2 sm:grid-cols-3 gap-4">
              {SUPPORTED_LANGUAGES.map((lang) => (
                <button key={lang.code} onClick={() => { setLanguage(lang); setShowLangPicker(false); }} className={`p-4 rounded-2xl text-center border-2 transition-all group ${language.code === lang.code ? 'border-emerald-500 bg-emerald-50 shadow-inner' : 'border-emerald-50 bg-white hover:border-emerald-200'}`}><p className="text-xl font-black text-emerald-900 mb-1">{lang.nativeName}</p><p className="text-[10px] text-emerald-400 font-bold uppercase tracking-widest">{lang.name}</p></button>
              ))}
            </div>
          </div>
        </div>
      )}

      {isScanning && (
        <div className="fixed inset-0 z-[100] bg-emerald-950/95 flex flex-col items-center justify-center p-8 backdrop-blur-sm text-center">
           <div className="w-72 h-72 border-4 border-emerald-400/20 rounded-full flex items-center justify-center animate-pulse mb-10 relative">
              <div className="absolute inset-0 rounded-full border-t-4 border-emerald-400 animate-spin"></div>
              <span className="text-8xl">🧬</span>
              <div className="absolute inset-x-0 top-1/2 scan-line bg-gradient-to-r from-transparent via-emerald-400 to-transparent h-1.5 w-full shadow-[0_0_20px_#10b981]"></div>
           </div>
           <p className="text-white text-3xl font-black mb-2 tracking-tight">KrishiX AI</p>
           <p className="text-emerald-400 font-bold uppercase tracking-[0.3em] text-[10px] animate-pulse">Running Diagnostic Protocols...</p>
        </div>
      )}

      {/* Floating Action Button (Concierge for Farmers) */}
      {role === UserRole.FARMER && (
        <button 
          onClick={() => setShowChat(true)}
          className="fixed bottom-24 right-6 w-16 h-16 bg-gradient-to-br from-emerald-500 to-teal-600 text-white rounded-full shadow-[0_15px_40px_rgba(16,185,129,0.4)] flex items-center justify-center transform hover:scale-110 active:scale-95 transition-all z-40"
        >
          <span className="text-3xl">🤖</span>
        </button>
      )}

      <ChatInterface isOpen={showChat} onClose={() => setShowChat(false)} currentLanguage={language} />
    </div>
  );
};

export default App;

import React, { useState, useEffect, useCallback } from 'react';
import ReactMarkdown from 'react-markdown';
import { AppMode, ModeConfig, HistoryItem, Language, SUPPORTED_LANGUAGES, UserRole, Listing } from './types';
import { ModeCard } from './components/ModeCard';
import { FileUpload } from './components/FileUpload';
import { ChatInterface } from './components/ChatInterface';
import { HistoryModal } from './components/HistoryModal';
import { 
  analyzeDiagnosticMedia, 
  getDailyTip, 
  generateSpeech,
  getLocalizedAdvisory,
  playPCM
} from './services/geminiService';
import { db, addListing, addHistory, LISTINGS_COLLECTION, HISTORY_COLLECTION } from './services/firebaseService';
import { collection, query, orderBy, onSnapshot, limit } from 'firebase/firestore';

const AI_MODES: ModeConfig[] = [
  {
    id: AppMode.CROP_DOCTOR,
    title: 'Crop Doctor',
    description: 'Pathology & nutrient scanning.',
    icon: '🌱',
    acceptedFileTypes: 'image/*',
    inputLabel: 'Scan Leaf',
  },
  {
    id: AppMode.VET_DERM,
    title: 'Derm-Scan',
    description: 'Livestock skin diagnostics.',
    icon: '🐄',
    acceptedFileTypes: 'image/*',
    inputLabel: 'Diagnostic Photo',
  },
  {
    id: AppMode.ANIMAL_BEHAVIOR,
    title: 'Animal Pulse',
    description: 'Stress & pain detection.',
    icon: '🐕',
    acceptedFileTypes: 'video/*,image/gif',
    inputLabel: 'Analysis',
  },
  {
    id: AppMode.MARKET_INSIGHTS,
    title: 'Market Intelligence',
    description: 'Prices & local news.',
    icon: '📈',
    inputLabel: 'Market Query',
    acceptedFileTypes: ''
  }
];

type TabType = 'home' | 'diagnostics' | 'stall' | 'history' | 'shop';

const App: React.FC = () => {
  const [role, setRole] = useState<UserRole | null>(null);
  const [activeTab, setActiveTab] = useState<TabType>('home');
  const [activeMode, setActiveMode] = useState<ModeConfig | null>(null);
  const [isScanning, setIsScanning] = useState(false);
  const [result, setResult] = useState<string | null>(null);
  const [language, setLanguage] = useState<Language>(SUPPORTED_LANGUAGES[0]);
  const [showLangPicker, setShowLangPicker] = useState(false);
  const [dailyTip, setDailyTip] = useState<string>('Welcome to Kisan-Rakshak AI...');
  const [toast, setToast] = useState<{message: string, type: 'success' | 'error'} | null>(null);

  const [localAdvisory, setLocalAdvisory] = useState<string | null>(null);
  const [localGrounding, setLocalGrounding] = useState<any[]>([]);
  const [locationLoading, setLocationLoading] = useState(false);

  const [showChat, setShowChat] = useState(false);
  const [history, setHistory] = useState<HistoryItem[]>([]);
  const [showHistory, setShowHistory] = useState(false);

  const [listings, setListings] = useState<Listing[]>([]);
  const [isAddingListing, setIsAddingListing] = useState(false);
  const [newListing, setNewListing] = useState<Partial<Listing>>({ category: 'Vegetable' });
  const [file, setFile] = useState<File | null>(null);
  const [previewUrl, setPreviewUrl] = useState<string | null>(null);

  useEffect(() => {
    if (toast) {
      const timer = setTimeout(() => setToast(null), 4000);
      return () => clearTimeout(timer);
    }
  }, [toast]);

  useEffect(() => {
    getDailyTip(language).then(setDailyTip);

    const listingsQuery = query(collection(db, LISTINGS_COLLECTION), orderBy("createdAt", "desc"));
    const unsubscribeListings = onSnapshot(listingsQuery, (snapshot) => {
      setListings(snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() })) as Listing[]);
    });

    const historyQuery = query(collection(db, HISTORY_COLLECTION), orderBy("timestamp", "desc"), limit(20));
    const unsubscribeHistory = onSnapshot(historyQuery, (snapshot) => {
      setHistory(snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() })) as HistoryItem[]);
    });

    return () => {
      unsubscribeListings();
      unsubscribeHistory();
    };
  }, [language]);

  const showToast = (message: string, type: 'success' | 'error' = 'success') => {
    setToast({ message, type });
  };

  const handleFetchLocalAdvisory = useCallback(() => {
    setLocationLoading(true);
    if (!navigator.geolocation) {
      showToast("Geolocation not supported", "error");
      setLocationLoading(false);
      return;
    }

    navigator.geolocation.getCurrentPosition(
      async (pos) => {
        try {
          const { latitude, longitude } = pos.coords;
          const advisoryData = await getLocalizedAdvisory(latitude, longitude, language);
          setLocalAdvisory(advisoryData.text);
          setLocalGrounding(advisoryData.urls);
        } catch (err) {
          showToast("Failed to fetch location data", "error");
        } finally {
          setLocationLoading(false);
        }
      },
      () => {
        showToast("Location permission denied", "error");
        setLocationLoading(false);
      }
    );
  }, [language]);

  const handleFileSelect = (f: File) => {
    setFile(f);
    setPreviewUrl(URL.createObjectURL(f));
  };

  const handleCreateListing = async () => {
    if (!newListing.name || !newListing.price || !file) {
      showToast("Please fill all fields and add a photo", "error");
      return;
    }

    setIsScanning(true);
    const reader = new FileReader();
    reader.onloadend = async () => {
      try {
        await addListing({
          name: newListing.name!,
          price: newListing.price!,
          category: newListing.category as any,
          image: reader.result as string,
          farmerName: 'Kisan Bharat'
        });
        showToast("Product listed in Bazaar!");
        setIsAddingListing(false);
        setActiveTab('stall');
      } catch (e) {
        showToast("Listing failed", "error");
      } finally {
        setIsScanning(false);
      }
    };
    reader.readAsDataURL(file);
  };

  const handleAnalyze = async () => {
    if (!activeMode) return;
    setIsScanning(true);
    try {
      let analysisText = "";
      if (activeMode.id === AppMode.MARKET_INSIGHTS) {
        analysisText = "Fetching live market rates for your region..."; // Fallback placeholder
      } else {
        if (!file) throw new Error("Please upload or take a photo first.");
        analysisText = await analyzeDiagnosticMedia(file, activeMode.id, language);
      }
      setResult(analysisText);
      await addHistory({
        timestamp: Date.now(),
        mode: activeMode.id,
        result: analysisText,
        previewText: analysisText.substring(0, 100) + "..."
      });
    } catch (err: any) {
      showToast(err.message, "error");
    } finally {
      setIsScanning(false);
    }
  };

  const handleBuyNow = (listing: Listing) => {
    const rzp = new (window as any).Razorpay({
      key: "rzp_test_R63nysub7CBtrS",
      amount: parseInt(listing.price) * 100,
      currency: "INR",
      name: "Kisan-Rakshak Bazaar",
      description: `Purchase: ${listing.name}`,
      handler: (res: any) => {
        showToast(`Order Confirmed! ID: ${res.razorpay_payment_id.substring(0,10)}`);
      },
      theme: { color: "#064e3b" }
    });
    rzp.open();
  };

  const NavButton = ({ tab, icon, label }: { tab: TabType, icon: string, label: string }) => {
    const isActive = activeTab === tab;
    return (
      <button 
        onClick={() => { setActiveTab(tab); setResult(null); setActiveMode(null); setIsAddingListing(false); }}
        className={`flex flex-col items-center justify-center flex-1 py-3 transition-all ${isActive ? 'text-emerald-900 scale-105' : 'text-emerald-400 opacity-60'}`}
      >
        <div className="text-2xl mb-1">{icon}</div>
        <span className={`text-[9px] font-black uppercase tracking-widest ${isActive ? 'opacity-100' : 'opacity-0 h-0 overflow-hidden'}`}>{label}</span>
      </button>
    );
  };

  if (!role) {
    return (
      <div className="min-h-screen bg-agri-ivory flex flex-col items-center justify-center p-6 bg-gradient-to-br from-emerald-50 via-white to-teal-50">
        <div className="max-w-md w-full text-center space-y-12 animate-fade-in">
          <div className="space-y-4">
            <div className="w-24 h-24 bg-gradient-to-br from-emerald-600 to-teal-700 rounded-[2.5rem] flex items-center justify-center text-5xl shadow-2xl mx-auto float">🌾</div>
            <h1 className="text-5xl font-black text-emerald-900 tracking-tighter">Kisan-Rakshak</h1>
            <p className="text-emerald-600 font-bold uppercase tracking-[0.3em] text-[10px]">Guardians of the Harvest</p>
          </div>

          <div className="grid grid-cols-1 gap-4">
            <button onClick={() => setRole(UserRole.FARMER)} className="bg-white border-2 border-emerald-100 p-8 rounded-[2.5rem] text-left hover:border-emerald-500 hover:shadow-2xl transition-all active:scale-95 group">
              <div className="flex items-center gap-6">
                <div className="w-16 h-16 bg-emerald-100 rounded-2xl flex items-center justify-center text-4xl group-hover:rotate-12 transition-transform">🚜</div>
                <div>
                  <h3 className="text-xl font-black text-emerald-900">I am a Farmer</h3>
                  <p className="text-sm text-emerald-600">Scan crops & sell directly.</p>
                </div>
              </div>
            </button>
            <button onClick={() => setRole(UserRole.CONSUMER)} className="bg-white border-2 border-teal-100 p-8 rounded-[2.5rem] text-left hover:border-teal-500 hover:shadow-2xl transition-all active:scale-95 group">
              <div className="flex items-center gap-6">
                <div className="w-16 h-16 bg-teal-100 rounded-2xl flex items-center justify-center text-4xl group-hover:-rotate-12 transition-transform">🧺</div>
                <div>
                  <h3 className="text-xl font-black text-emerald-900">I am a Consumer</h3>
                  <p className="text-sm text-emerald-600">Shop fresh, pure produce.</p>
                </div>
              </div>
            </button>
          </div>

          <button onClick={() => setShowLangPicker(true)} className="text-emerald-400 font-bold uppercase tracking-widest text-[10px] flex items-center gap-2 mx-auto">🌐 Language: {language.nativeName}</button>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-agri-ivory flex flex-col font-sans pb-24">
      {toast && (
        <div className={`fixed top-6 left-1/2 -translate-x-1/2 z-[200] px-6 py-3 rounded-2xl shadow-2xl animate-bounce text-white font-bold flex items-center gap-3 ${toast.type === 'error' ? 'bg-red-600' : 'bg-emerald-900'}`}>
          <span>{toast.type === 'error' ? '❌' : '✅'}</span>
          {toast.message}
        </div>
      )}

      <header className="glass sticky top-0 z-50 border-b border-emerald-100">
        <div className="max-w-2xl mx-auto px-4 h-20 flex items-center justify-between">
          <div className="flex items-center gap-3 cursor-pointer" onClick={() => { setRole(null); setActiveTab('home'); }}>
            <div className="w-10 h-10 bg-gradient-to-br from-emerald-500 to-teal-600 rounded-xl flex items-center justify-center text-xl shadow-lg">🌾</div>
            <h1 className="text-lg font-black text-emerald-900 leading-none">Kisan-Rakshak</h1>
          </div>
          <button onClick={() => setShowLangPicker(true)} className="p-2.5 bg-white border border-emerald-100 rounded-2xl shadow-sm hover:bg-emerald-50 transition-all flex items-center gap-2">
            <span className="text-lg">🌐</span>
            <span className="text-[10px] font-black uppercase text-emerald-900 hidden sm:block">{language.nativeName}</span>
          </button>
        </div>
      </header>

      <main className="flex-grow max-w-2xl mx-auto w-full p-4 py-6">
        {role === UserRole.FARMER && activeTab === 'home' && !result && !activeMode && (
          <div className="space-y-8 animate-fade-in">
            <section className="glass p-8 rounded-[3rem] border-teal-100 bg-gradient-to-br from-teal-50/50 to-white shadow-xl">
              <div className="flex items-center justify-between mb-6">
                <div className="flex items-center gap-4">
                  <div className="w-12 h-12 bg-teal-100 rounded-2xl flex items-center justify-center text-2xl">🌦️</div>
                  <div>
                    <h2 className="text-xl font-black text-emerald-900">Local Advisory</h2>
                    <p className="text-[10px] font-bold text-teal-600 uppercase tracking-widest">Ground Intelligence</p>
                  </div>
                </div>
                <button onClick={handleFetchLocalAdvisory} disabled={locationLoading} className="px-4 py-2 bg-teal-100 text-teal-700 rounded-xl text-xs font-bold hover:bg-teal-200 transition-all">
                  {locationLoading ? "Analyzing..." : "Refresh"}
                </button>
              </div>
              {localAdvisory ? (
                <div className="prose prose-sm prose-teal max-w-none text-emerald-900 leading-relaxed font-medium">
                  <ReactMarkdown>{localAdvisory}</ReactMarkdown>
                </div>
              ) : (
                <div className="text-center py-6 text-emerald-600 font-medium italic">Grant location for personalized farming advice.</div>
              )}
            </section>

            <section className="bg-amber-50 p-6 rounded-[2rem] border border-amber-100 space-y-1">
              <p className="text-[9px] font-black text-amber-600 uppercase tracking-widest">Daily Farming Insight</p>
              <p className="text-emerald-900 font-bold leading-tight">{dailyTip}</p>
            </section>
          </div>
        )}

        {activeTab === 'diagnostics' && !result && !activeMode && (
          <div className="grid grid-cols-2 gap-4 animate-fade-in">
            <div className="col-span-2 px-2 mb-2">
              <h2 className="text-2xl font-black text-emerald-900">AI Expert Suite</h2>
              <p className="text-sm text-emerald-600 font-medium">Select a specialized neural module.</p>
            </div>
            {AI_MODES.map(m => <ModeCard key={m.id} mode={m} onClick={setActiveMode} />)}
          </div>
        )}

        {activeTab === 'stall' && !isAddingListing && (
          <div className="space-y-6 animate-fade-in">
            <div className="px-2">
              <h2 className="text-2xl font-black text-emerald-900">My Stall</h2>
              <p className="text-sm text-emerald-600 font-medium">Sell directly to thousands of consumers.</p>
            </div>
            <button onClick={() => setIsAddingListing(true)} className="w-full p-12 bg-white border-3 border-dashed border-emerald-100 rounded-[3rem] flex flex-col items-center gap-4 hover:bg-emerald-50 transition-all shadow-inner">
              <div className="text-5xl">🏪</div>
              <p className="font-black text-emerald-900">List New Produce</p>
            </button>
          </div>
        )}

        {role === UserRole.CONSUMER && activeTab === 'shop' && (
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-6 animate-fade-in pb-20">
            <div className="col-span-full py-4">
              <h2 className="text-4xl font-black text-emerald-900 text-center">Fresh Bazaar</h2>
              <p className="text-emerald-600 text-center font-medium">Pure quality from rural hearts.</p>
            </div>
            {listings.map(l => (
              <div key={l.id} className="bg-white rounded-[2.5rem] overflow-hidden shadow-2xl border border-emerald-50 group hover:-translate-y-2 transition-all">
                <img src={l.image} className="w-full h-52 object-cover" alt={l.name} />
                <div className="p-6 space-y-4">
                  <div className="flex justify-between items-start">
                    <div>
                      <h3 className="font-bold text-emerald-900 text-xl">{l.name}</h3>
                      <p className="text-[10px] text-emerald-500 font-black uppercase">Farmer: {l.farmerName}</p>
                    </div>
                    <div className="text-2xl font-black text-emerald-900">₹{l.price}</div>
                  </div>
                  <button onClick={() => handleBuyNow(l)} className="w-full py-4 bg-emerald-900 text-white rounded-2xl font-bold shadow-xl active:scale-95 transition-all">Buy Now</button>
                </div>
              </div>
            ))}
          </div>
        )}

        {isAddingListing && (
          <div className="animate-slide-up space-y-6">
            <h2 className="text-2xl font-black text-emerald-900 px-2">New Listing</h2>
            <div className="glass rounded-[3rem] p-8 space-y-6 shadow-2xl">
              <FileUpload label="Snap Product" acceptedTypes="image/*" onFileSelect={handleFileSelect} />
              <input type="text" onChange={(e) => setNewListing({...newListing, name: e.target.value})} placeholder="Item Name" className="w-full p-5 bg-emerald-50/50 rounded-2xl border border-emerald-100 font-bold" />
              <div className="flex gap-4">
                <input type="number" onChange={(e) => setNewListing({...newListing, price: e.target.value})} placeholder="Price (₹)" className="w-full p-5 bg-emerald-50/50 rounded-2xl border border-emerald-100 font-bold" />
                <select onChange={(e) => setNewListing({...newListing, category: e.target.value as any})} className="w-full p-5 bg-emerald-50/50 rounded-2xl border border-emerald-100 font-bold">
                  <option value="Vegetable">Vegetable</option>
                  <option value="Dairy">Dairy</option>
                </select>
              </div>
              <button onClick={handleCreateListing} className="w-full py-6 bg-emerald-900 text-white rounded-[2rem] font-bold text-lg active:scale-95 transition-all">Launch to Bazaar 🚀</button>
            </div>
          </div>
        )}

        {activeMode && !result && !isScanning && (
          <div className="animate-slide-up space-y-6">
            <h2 className="text-2xl font-black text-emerald-900 px-2">{activeMode.title}</h2>
            <div className="glass rounded-[3rem] p-10 space-y-8 shadow-2xl">
              <FileUpload label={activeMode.inputLabel || "Select Media"} acceptedTypes={activeMode.acceptedFileTypes || "*"} onFileSelect={handleFileSelect} />
              <button onClick={handleAnalyze} className="w-full py-6 bg-emerald-900 text-white rounded-[2rem] font-bold text-lg active:scale-95 transition-all">Start Neural Scan</button>
            </div>
          </div>
        )}

        {result && (
          <div className="animate-fade-in space-y-6 pb-20">
            <div className="bg-white rounded-[2.5rem] p-6 shadow-2xl border border-emerald-100 flex gap-6 items-center">
              {previewUrl && <img src={previewUrl} className="w-24 h-24 rounded-2xl object-cover border-2 border-emerald-50 shadow-inner" alt="Sample" />}
              <div className="flex-1">
                <span className="px-3 py-1 bg-emerald-100 text-emerald-600 rounded-full text-[10px] font-black uppercase tracking-widest">Diagnostic Verified</span>
                <p className="text-lg font-black text-emerald-900 leading-tight">Expert Report Ready</p>
              </div>
            </div>
            <div className="glass p-8 rounded-[3rem] shadow-xl border-emerald-50 bg-white/50">
              <div className="prose prose-emerald prose-sm max-w-none prose-headings:text-emerald-900 prose-headings:font-black prose-p:text-emerald-800 font-medium">
                <ReactMarkdown>{result}</ReactMarkdown>
              </div>
              <p className="mt-8 pt-4 border-t border-emerald-100 text-[10px] text-red-400 font-bold uppercase italic">*Disclaimer: This is AI advice. Consult a local professional for critical cases.</p>
            </div>
