import { GoogleGenAI, Modality } from "@google/genai";
import { AppMode, Language } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const callAiWithRetry = async <T>(fn: () => Promise<T>, retries = 3, initialDelay = 1000): Promise<T> => {
  let lastError: any;
  for (let i = 0; i < retries; i++) {
    try {
      return await fn();
    } catch (error: any) {
      lastError = error;
      const status = error?.status || (error as any)?.response?.status;
      if (status === 500 || status === 429 || !status) {
        const delay = initialDelay * Math.pow(2, i);
        await new Promise(resolve => setTimeout(resolve, delay));
        continue;
      }
      throw error;
    }
  }
  throw lastError;
};

const blobToBase64 = (blob: Blob): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onloadend = () => {
      if (typeof reader.result === 'string') {
        resolve(reader.result.split(',')[1]);
      } else {
        reject(new Error("Base64 failed"));
      }
    };
    reader.onerror = reject;
    reader.readAsDataURL(blob);
  });
};

function decodeBase64(base64: string): Uint8Array {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

async function decodeAudioData(data: Uint8Array, ctx: AudioContext, sampleRate: number, numChannels: number): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);
  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

let audioContext: AudioContext | null = null;

export const playPCM = async (base64Audio: string) => {
  try {
    if (!audioContext) audioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
    if (audioContext.state === 'suspended') await audioContext.resume();
    const buffer = await decodeAudioData(decodeBase64(base64Audio), audioContext, 24000, 1);
    const source = audioContext.createBufferSource();
    source.buffer = buffer;
    source.connect(audioContext.destination);
    source.start();
  } catch (error) {
    console.error("Audio error:", error);
  }
};

export const getDailyTip = async (lang: Language): Promise<string> => {
  return callAiWithRetry(async () => {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Short one-sentence farming tip for today in ${lang.name} and English.`,
    });
    return response.text || "Monitor crops for pests daily.";
  });
};

export const getLocalizedAdvisory = async (lat: number, lng: number, lang: Language): Promise<{text: string, urls: any[]}> => {
  return callAiWithRetry(async () => {
    const prompt = `Search weather and agricultural news for coordinates [${lat}, ${lng}]. 
    Provide a 3-step farmer action plan in ${lang.name} and English. Use Emojis. Focus on immediate tasks like irrigation or harvest based on current rain forecast.`;
    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: prompt,
      config: { tools: [{ googleSearch: {} }] }
    });
    const urls = response.candidates?.[0]?.groundingMetadata?.groundingChunks
      ?.map((c: any) => c.web ? { title: c.web.title, uri: c.web.uri } : null)
      .filter(Boolean) || [];
    return { text: response.text || "Intelligence offline.", urls };
  });
};

export const analyzeDiagnosticMedia = async (file: File, mode: AppMode, lang: Language): Promise<string> => {
  const base64Data = await blobToBase64(file);
  const mimeType = file.type;
  const context = mode === AppMode.CROP_DOCTOR ? "Plant Pathologist" : "Veterinary Doctor";
  const protocol = `ROLE: You are an expert ${context}. Provide a structured diagnostic report in ${lang.name} and English:
  1. Diagnosis (निदान)
  2. Clinical Observations (लक्षणे)
  3. Severity Level (तीव्रता)
  4. Immediate Action Plan (तात्काळ कृती योजना)
  5. Prevention Tips (प्रतिबंधात्मक उपाय)
  Format as clean Markdown with bold headers.`;

  return callAiWithRetry(async () => {
    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: {
        parts: [{ inlineData: { data: base64Data, mimeType } }, { text: protocol }]
      },
      config: { temperature: 0.1, thinkingConfig: { thinkingBudget: 1000 } }
    });
    return response.text || "Scan inconclusive. Take another photo.";
  });
};

export const generateSpeech = async (text: string, lang: Language): Promise<string | null> => {
  const cleanText = text.replace(/[#*`-]/g, '').substring(0, 300);
  return callAiWithRetry(async () => {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: { parts: [{ text: `Read this in ${lang.name}: ${cleanText}` }] },
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Kore' } } },
      },
    });
    return response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data || null;
  });
};

export const chatWithAI = async (history: any[], message: string, lang: Language): Promise<string> => {
  return callAiWithRetry(async () => {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: [...history, { role: 'user', parts: [{ text: message }] }],
      config: { systemInstruction: `You are the KrishiX Concierge. Expert, helpful, and empathetic. Answer in ${lang.name} and English.` }
    });
    return response.text || "I'm here for your farm.";
  });
};

export const transcribeAudio = async (blob: Blob): Promise<string> => {
  const base64Data = await blobToBase64(blob);
  return callAiWithRetry(async () => {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: { parts: [{ inlineData: { data: base64Data, mimeType: 'audio/wav' } }, { text: "Transcribe farmer query." }] }
    });
    return response.text || "";
  });
};

import React, { useState, useRef, useEffect } from 'react';
import { ChatMessage, Language } from '../types';
import { chatWithAI, transcribeAudio } from '../services/geminiService';
import { AudioRecorder } from './AudioRecorder';

interface ChatInterfaceProps {
  isOpen: boolean;
  onClose: () => void;
  currentLanguage: Language;
}

export const ChatInterface: React.FC<ChatInterfaceProps> = ({ isOpen, onClose, currentLanguage }) => {
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [isTranscribing, setIsTranscribing] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (messages.length === 0) {
       const welcomeText = currentLanguage.code === 'en' 
         ? "Namaste! I am your KrishiX AI. How can I assist you with your farm today?"
         : `नमस्ते! मी तुमचा KrishiX AI आहे. मी तुम्हाला तुमच्या शेतीसाठी कशी मदत करू शकतो? (${currentLanguage.nativeName})`;
       setMessages([{ role: 'model', text: welcomeText }]);
    }
  }, [currentLanguage]);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, isOpen]);

  const handleSend = async (textToSend?: string) => {
    const text = textToSend || input;
    if (!text.trim() || isLoading) return;

    const userMsg: ChatMessage = { role: 'user', text: text };
    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsLoading(true);

    try {
      const history = messages.map(m => ({ role: m.role, parts: [{ text: m.text }] }));
      const responseText = await chatWithAI(history, text, currentLanguage);
      setMessages(prev => [...prev, { role: 'model', text: responseText }]);
    } catch (e: any) {
      setMessages(prev => [...prev, { role: 'model', text: "Service is busy. Retrying..." }]);
    } finally {
      setIsLoading(false);
    }
  };

  const handleAudioTranscription = async (blob: Blob) => {
    setIsTranscribing(true);
    setIsLoading(true);
    try {
      const transcribedText = await transcribeAudio(blob);
      if (transcribedText) setInput(transcribedText);
    } catch (e) {
      alert("Could not transcribe voice.");
    } finally {
      setIsTranscribing(false);
      setIsLoading(false);
    }
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-[100] bg-emerald-950/80 backdrop-blur-md flex items-end sm:items-center justify-center p-0 sm:p-4">
      <div className="bg-white w-full h-[92vh] sm:h-[650px] sm:max-w-md rounded-t-[3rem] sm:rounded-[3rem] flex flex-col shadow-2xl overflow-hidden animate-slide-up border border-white/20">
        <div className="bg-gradient-to-br from-emerald-500 to-teal-600 p-5 flex justify-between items-center text-white shrink-0">
          <div className="flex items-center space-x-3">
            <div className="w-12 h-12 bg-white/20 rounded-2xl flex items-center justify-center text-2xl">🤖</div>
            <div>
              <h3 className="font-bold text-lg leading-none">KrishiX AI</h3>
              <p className="text-[10px] uppercase font-bold text-emerald-100 tracking-widest mt-1">Live in {currentLanguage.nativeName}</p>
            </div>
          </div>
          <button onClick={onClose} className="p-3 bg-white/10 hover:bg-white/20 rounded-2xl transition-all">
            <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M6 18L18 6M6 6l12 12" />
            </svg>
          </button>
        </div>

        <div ref={scrollRef} className="flex-1 overflow-y-auto p-5 space-y-4 bg-emerald-50/30 custom-scrollbar">
          {messages.map((msg, idx) => (
            <div key={idx} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
              <div className={`max-w-[85%] rounded-[2rem] p-4 text-sm leading-relaxed shadow-sm ${
                msg.role === 'user' 
                  ? 'bg-emerald-800 text-white rounded-br-none' 
                  : 'bg-white text-emerald-900 border border-emerald-100 rounded-bl-none font-medium'
              }`}>
                {msg.text}
              </div>
            </div>
          ))}
          {isLoading && !isTranscribing && (
            <div className="flex justify-start">
              <div className="bg-white p-4 rounded-3xl rounded-bl-none border border-emerald-100 flex space-x-2">
                <div className="w-2 h-2 bg-emerald-400 rounded-full animate-bounce"></div>
                <div className="w-2 h-2 bg-emerald-400 rounded-full animate-bounce delay-150"></div>
                <div className="w-2 h-2 bg-emerald-400 rounded-full animate-bounce delay-300"></div>
              </div>
            </div>
          )}
        </div>

        <div className="p-5 bg-white border-t border-emerald-50 flex flex-col space-y-4 shrink-0">
          {isTranscribing && (
             <div className="flex items-center gap-3 px-4 py-2 bg-emerald-50 rounded-full">
                <div className="w-3 h-3 bg-emerald-500 rounded-full animate-ping"></div>
                <span className="text-xs font-bold text-emerald-600 uppercase tracking-widest">Listening...</span>
             </div>
          )}
          <div className="flex items-center space-x-3">
            <AudioRecorder onRecordingComplete={handleAudioTranscription} isProcessing={isLoading} />
            <input
              type="text"
              value={input}
              onChange={(e) => setInput(e.target.value)}
              onKeyPress={(e) => e.key === 'Enter' && handleSend()}
              placeholder="Ask me anything..."
              className="flex-1 bg-emerald-50/50 border-2 border-emerald-50 rounded-full px-6 py-4 text-sm focus:outline-none focus:ring-4 focus:ring-emerald-500/10 focus:border-emerald-500 transition-all font-medium text-emerald-900"
              disabled={isLoading}
            />
            <button onClick={() => handleSend()} disabled={!input.trim() || isLoading} className="p-4 bg-emerald-900 text-white rounded-full hover:bg-emerald-800 disabled:opacity-30 transition-all shadow-xl active:scale-90">
              <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 12h14M12 5l7 7-7 7" />
              </svg>
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

