            <div className="w-24 h-24 bg-agri-forest rounded-[2.5rem] flex items-center justify-center text-5xl shadow-2xl mx-auto mb-6">🌾</div>
            <h1 className="text-5xl font-black text-agri-forest tracking-tighter">KrishiX</h1>
            <p className="text-agri-moss font-bold uppercase tracking-[0.2em] text-[10px]">Precision D2C Marketplace</p>
          </div>

          <div className="grid gap-4">
            <button onClick={() => setRole(UserRole.CONSUMER)} className="p-8 bg-white border-2 border-agri-sand rounded-[2.5rem] text-left hover:border-agri-leaf transition-all shadow-sm flex items-center gap-6 group active:scale-95">
              <div className="w-16 h-16 bg-agri-ivory rounded-2xl flex items-center justify-center text-3xl group-hover:rotate-12 transition-transform">🧺</div>
              <div><h3 className="font-black text-xl text-agri-forest">I want to Buy</h3><p className="text-sm text-agri-moss opacity-70">Direct from farmers.</p></div>
            </button>
            <button onClick={() => setRole(UserRole.FARMER)} className="p-8 bg-white border-2 border-agri-sand rounded-[2.5rem] text-left hover:border-agri-leaf transition-all shadow-sm flex items-center gap-6 group active:scale-95">
              <div className="w-16 h-16 bg-agri-ivory rounded-2xl flex items-center justify-center text-3xl group-hover:-rotate-12 transition-transform">🚜</div>
              <div><h3 className="font-black text-xl text-agri-forest">I want to Sell</h3><p className="text-sm text-agri-moss opacity-70">List products & use AI tools.</p></div>
            </button>
          </div>
        </motion.div>
      </div>
    );
  }

  return (
    <div className="min-h-screen pb-24 font-sans bg-slate-50">
      {/* Toast Notification */}
      <AnimatePresence>
        {toast && (
          <motion.div initial={{ opacity: 0, y: -50 }} animate={{ opacity: 1, y: 0 }} exit={{ opacity: 0, y: -50 }} 
            className={`fixed top-6 left-1/2 -translate-x-1/2 z-[200] px-6 py-4 rounded-2xl shadow-2xl text-white font-bold flex items-center gap-3 ${toast.type === 'error' ? 'bg-red-600' : 'bg-agri-forest'}`}>
            {toast.type === 'error' ? <Info className="w-5 h-5" /> : <CheckCircle className="w-5 h-5" />}
            {toast.msg}
          </motion.div>
        )}
      </AnimatePresence>

      <header className="glass sticky top-0 z-50 p-4 border-b border-agri-sand/30">
        <div className="max-w-2xl mx-auto flex items-center justify-between">
          <div className="flex items-center gap-3 cursor-pointer" onClick={() => { setRole(null); setActiveTab('home'); }}>
            <div className="w-10 h-10 bg-agri-forest rounded-xl flex items-center justify-center text-xl shadow-lg">🌾</div>
            <h1 className="text-xl font-black text-agri-forest leading-none">KrishiX</h1>
          </div>
          <div className="flex items-center gap-2">
            {role === UserRole.CONSUMER && (
              <button onClick={() => setIsCartOpen(true)} className="relative p-3 bg-agri-sand/50 rounded-full hover:bg-agri-sand transition-all active:scale-90">
                <ShoppingCart className="w-6 h-6 text-agri-forest" />
                {cart.length > 0 && <span className="absolute -top-1 -right-1 bg-red-500 text-white text-[10px] w-5 h-5 flex items-center justify-center rounded-full border-2 border-white font-black">{cart.length}</span>}
              </button>
            )}
            <button onClick={() => setShowChat(true)} className="p-3 bg-agri-forest/5 rounded-full hover:bg-agri-forest/10"><Zap className="w-6 h-6 text-agri-forest" /></button>
          </div>
        </div>
      </header>

      <main className="max-w-2xl mx-auto p-4 py-6">
        {role === UserRole.CONSUMER && activeTab === 'home' && (
