                <p className="text-[10px] font-black uppercase tracking-[0.3em] opacity-60">Featured Farmers</p>
                <h2 className="text-3xl font-black leading-tight">Harvested Today,<br/>On your table tomorrow.</h2>
                <button className="mt-4 flex items-center gap-2 text-xs font-black bg-white/20 px-4 py-2 rounded-full backdrop-blur-md">Explore Now <ArrowRight className="w-4 h-4" /></button>
              </div>
