                  <p className="text-[10px] text-agri-moss font-black uppercase tracking-widest">Global Marketplace Visibility</p>
                </div>
              </div>
              <button onClick={() => setIsAddingListing(false)} className="p-3 bg-agri-ivory rounded-2xl text-agri-forest">✕</button>
            </div>
            <div className="space-y-8">
              <FileUpload label="Show your produce" acceptedTypes="image/*" onFileSelect={(f) => {
                const reader = new FileReader();
                reader.onloadend = () => setNewListingForm(prev => ({ ...prev, image: reader.result as string }));
                reader.readAsDataURL(f);
              }} />
              <div className="space-y-4">
                <label className="text-[10px] font-black uppercase text-agri-moss tracking-widest pl-2">Product Details</label>
                <input type="text" placeholder="Item Name (e.g., Cherry Tomatoes)" value={newListingForm.name} onChange={(e) => setNewListingForm(p => ({ ...p, name: e.target.value }))}
                  className="w-full p-6 bg-agri-ivory/50 rounded-3xl border-2 border-agri-sand focus:border-agri-forest outline-none font-bold text-lg text-agri-forest" />

                <div className="grid grid-cols-2 gap-4">
                  <div className="space-y-2">
                    <input type="number" placeholder="Price (₹)" onChange={(e) => setNewListingForm(p => ({ ...p, price: parseInt(e.target.value) || 0 }))}
                      className="w-full p-6 bg-agri-ivory/50 rounded-3xl border-2 border-agri-sand focus:border-agri-forest outline-none font-bold text-lg text-agri-forest" />
                  </div>
                  <div className="space-y-2">
                    <select onChange={(e) => setNewListingForm(p => ({ ...p, unit: e.target.value as any }))}
                      className="w-full p-6 bg-agri-ivory/50 rounded-3xl border-2 border-agri-sand focus:border-agri-forest outline-none font-black text-agri-forest">
                      <option value="kg">per kg</option>
                      <option value="ltr">per liter</option>
                      <option value="bunch">per bunch</option>
                      <option value="dozen">per dozen</option>
                    </select>
                  </div>
                </div>

                <select onChange={(e) => setNewListingForm(p => ({ ...p, category: e.target.value as any }))}
                  className="w-full p-6 bg-agri-ivory/50 rounded-3xl border-2 border-agri-sand focus:border-agri-forest outline-none font-black text-agri-forest">
                  {CATEGORIES.map(c => <option key={c} value={c}>{c}</option>)}
                </select>

                <div className="bg-agri-ivory p-6 rounded-3xl border-2 border-agri-sand flex items-center justify-between">
                  <div className="flex items-center gap-3">
                    <ShieldCheck className="w-6 h-6 text-agri-moss" />
                    <div>
                      <p className="font-black text-agri-forest text-sm">AI Verification</p>
                      <p className="text-[8px] font-bold text-agri-moss uppercase">Boost trust by 40%</p>
                    </div>
                  </div>
                  <input type="checkbox" checked={newListingForm.certified} onChange={(e) => setNewListingForm(p => ({ ...p, certified: e.target.checked }))} 
                    className="w-6 h-6 accent-agri-forest cursor-pointer" />
                </div>
              </div>

              <button onClick={async () => {
                if (!newListingForm.name || !newListingForm.image) {
                  showToast("Photo and name are mandatory", "error");
                  return;
                }
                try {
                  await addListing({ ...newListingForm, farmerName: 'Bharat Sahil', createdAt: new Date().toISOString() });
                  setIsAddingListing(false);
                  showToast("Successfully listed!");
                } catch (e) {
                  showToast("Listing failed", "error");
                }
              }} className="w-full py-6 bg-agri-forest text-white rounded-[2.5rem] font-black text-xl shadow-2xl active:scale-95 transition-all">List on Bazaar 🚀</button>
            </div>
          </motion.div>
        </div>
      )}

      <ChatInterface isOpen={showChat} onClose={() => setShowChat(false)} currentLanguage={language} />
    </div>
  );
};

export default App;

