              <button onClick={() => setActiveTab('home')} className={`flex flex-col items-center gap-1 transition-all ${activeTab === 'home' ? 'text-agri-forest scale-110' : 'text-agri-moss opacity-30 hover:opacity-100'}`}><LayoutDashboard className="w-6 h-6" /><span className="text-[9px] font-black uppercase tracking-tighter">Sales</span></button>
              <button onClick={() => setActiveTab('stall')} className={`flex flex-col items-center gap-1 transition-all ${activeTab === 'stall' ? 'text-agri-forest scale-110' : 'text-agri-moss opacity-30 hover:opacity-100'}`}><Store className="w-6 h-6" /><span className="text-[9px] font-black uppercase tracking-tighter">Stall</span></button>
              <button onClick={() => setActiveTab('smart')} className={`flex flex-col items-center gap-1 transition-all ${activeTab === 'smart' ? 'text-agri-forest scale-110' : 'text-agri-moss opacity-30 hover:opacity-100'}`}><Sprout className="w-6 h-6" /><span className="text-[9px] font-black uppercase tracking-tighter">Smart AI</span></button>
              <button onClick={() => setRole(null)} className="flex flex-col items-center gap-1 text-agri-moss opacity-30"><User className="w-6 h-6" /><span className="text-[9px] font-black uppercase tracking-tighter">Exit</span></button>
            </>
