                      </div>
                      <div className="flex items-center gap-4 bg-white p-2 rounded-2xl shadow-inner border border-agri-sand">
                        <button onClick={() => setCart(prev => prev.map(i => i.listingId === item.listingId ? { ...i, quantity: Math.max(0, i.quantity - 1) } : i).filter(i => i.quantity > 0))} className="w-10 h-10 rounded-xl bg-agri-ivory flex items-center justify-center font-black text-agri-forest hover:bg-agri-sand transition-all">-</button>
                        <span className="font-black w-6 text-center text-lg">{item.quantity}</span>
                        <button onClick={() => setCart(prev => prev.map(i => i.listingId === item.listingId ? { ...i, quantity: i.quantity + 1 } : i))} className="w-10 h-10 rounded-xl bg-agri-forest text-white flex items-center justify-center font-black shadow-lg transition-all">+</button>
                      </div>
                    </div>
                  ))
