};

// Singleton initialization pattern
const app = !getApps().length ? initializeApp(firebaseConfig) : getApp();
export const db = getFirestore(app);

export const LISTINGS_COLLECTION = "listings";
export const HISTORY_COLLECTION = "history";
export const ORDERS_COLLECTION = "orders";

export const addListing = async (listing: any) => {
  return addDoc(collection(db, LISTINGS_COLLECTION), {
    ...listing,
    createdAt: serverTimestamp()
  });
};

export const updateListing = async (id: string, updates: any) => {
  const docRef = doc(db, LISTINGS_COLLECTION, id);
  return updateDoc(docRef, updates);
};

export const deleteListing = async (id: string) => {
  const docRef = doc(db, LISTINGS_COLLECTION, id);
  return deleteDoc(docRef);
};

export const addOrder = async (order: any) => {
  return addDoc(collection(db, ORDERS_COLLECTION), {
    ...order,
    timestamp: Date.now(),
    status: 'Pending',
    createdAt: serverTimestamp()
  });
};

export const updateOrderStatus = async (orderId: string, status: string) => {
  const docRef = doc(db, ORDERS_COLLECTION, orderId);
  return updateDoc(docRef, { status });
};

export const addHistory = async (historyItem: any) => {
  return addDoc(collection(db, HISTORY_COLLECTION), {
    ...historyItem,
    createdAt: serverTimestamp()
  });
};

