import { 
  ShoppingBag, 
  LayoutDashboard, 
  Store, 
  Sprout, 
  User, 
  Search, 
  ShoppingCart, 
  ChevronRight,
  TrendingUp,
  PackageCheck,
  Zap,
  CheckCircle,
  Clock,
  MapPin,
  Plus,
  ArrowRight,
  ShieldCheck,
  Info
} from 'lucide-react';

import { 
  UserRole, 
  Listing, 
  Order, 
  CartItem, 
  ProductCategory, 
  SUPPORTED_LANGUAGES, 
  Language,
  AppMode,
  ModeConfig
} from './types';
import { 
  db, 
  LISTINGS_COLLECTION, 
  ORDERS_COLLECTION, 
  addOrder, 
  updateOrderStatus, 
  deleteListing, 
  addListing 
} from './services/firebaseService';
import { 
  analyzeDiagnosticMedia, 
  generateSpeech, 
  playPCM 
} from './services/geminiService';
import { ChatInterface } from './components/ChatInterface';
import { FileUpload } from './components/FileUpload';
import { Spinner } from './components/Spinner';
import ReactMarkdown from 'react-markdown';

// Component aliases to bypass specific environment type resolution issues
const MotionDiv = motion.div as any;

const CATEGORIES: ProductCategory[] = ['Vegetable', 'Fruit', 'Dairy', 'Grains'];

const AI_MODES: ModeConfig[] = [
  { id: AppMode.CROP_DOCTOR, title: 'Crop Doctor', description: 'Pathology scanning.', icon: '🌱' },
  { id: AppMode.VET_DERM, title: 'Livestock Scan', description: 'Skin health diagnostic.', icon: '🐄' },
  { id: AppMode.ANIMAL_BEHAVIOR, title: 'Behavior Analysis', description: 'Stress detection.', icon: '🐕' }
];

const App: React.FC = () => {
  const [role, setRole] = useState<UserRole | null>(null);
  const [activeTab, setActiveTab] = useState<string>('home');
  const [language, setLanguage] = useState<Language>(SUPPORTED_LANGUAGES[0]);
  const [listings, setListings] = useState<Listing[]>([]);
  const [orders, setOrders] = useState<Order[]>([]);
  const [cart, setCart] = useState<CartItem[]>([]);

  const [newListingForm, setNewListingForm] = useState<Partial<Listing>>({
    name: '',
    price: 0,
    category: 'Vegetable',
    unit: 'kg',
    stockQuantity: 10,
    description: '',
    certified: false
  });

  const [isCartOpen, setIsCartOpen] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');
  const [activeCategory, setActiveCategory] = useState<ProductCategory | 'All'>('All');
  const [isAddingListing, setIsAddingListing] = useState(false);
  const [activeAiMode, setActiveAiMode] = useState<ModeConfig | null>(null);
  const [aiResult, setAiResult] = useState<string | null>(null);
  const [isScanning, setIsScanning] = useState(false);
  const [showChat, setShowChat] = useState(false);
  const [toast, setToast] = useState<{msg: string, type: 'success' | 'error'} | null>(null);

  useEffect(() => {
    // Fix: Use Firestore v8 namespaced API to resolve "no exported member" errors for onSnapshot, query, etc.
    const unsubListings = db.collection(LISTINGS_COLLECTION)
      .orderBy('createdAt', 'desc')
      .onSnapshot((snap) => {
        setListings(snap.docs.map(doc => ({ id: doc.id, ...doc.data() })) as Listing[]);
      }, (error) => console.error("Listing Stream Error:", error));

    const unsubOrders = db.collection(ORDERS_COLLECTION)
      .orderBy('timestamp', 'desc')
      .onSnapshot((snap) => {
        setOrders(snap.docs.map(doc => ({ id: doc.id, ...doc.data() })) as Order[]);
      }, (error) => console.error("Order Stream Error:", error));

    return () => { 
      unsubListings(); 
      unsubOrders(); 
    };
  }, []);

  const showToast = useCallback((msg: string, type: 'success' | 'error' = 'success') => {
    setToast({ msg, type });
    setTimeout(() => setToast(null), 3000);
  }, []);

  const addToCart = (product: Listing) => {
    setCart(prev => {
      const existing = prev.find(i => i.listingId === product.id);
      if (existing) return prev.map(i => i.listingId === product.id ? { ...i, quantity: i.quantity + 1 } : i);
      return [...prev, { listingId: product.id, name: product.name, price: product.price, quantity: 1, unit: product.unit, image: product.image }];
    });
    showToast(`Added ${product.name} to cart`);
  };

  const handleCheckout = async () => {
    if (cart.length === 0) return;
    const total = cart.reduce((sum, item) => sum + (item.price * item.quantity), 0);

    if (!(window as any).Razorpay) {
      showToast("Payment service offline", "error");
      return;
    }

    const rzp = new (window as any).Razorpay({
      key: "rzp_test_R63nysub7CBtrS",
      amount: total * 100,
      currency: "INR",
      name: "KrishiX Bazaar",
      handler: async () => {
        try {
          await addOrder({ 
            items: cart, 
            totalPrice: total, 
            customerName: 'Bharat Sahil', 
            customerAddress: '123 Agri Lane, Pune' 
          });
          setCart([]);
          setIsCartOpen(false);
          showToast("Order Placed Successfully!");
        } catch (e) {
          showToast("Order failed to save", "error");
        }
      }
    });
    rzp.open();
  };

  const handleAiScan = async (file: File) => {
    if (!activeAiMode) return;
    setIsScanning(true);
    setAiResult(null);
    try {
      const result = await analyzeDiagnosticMedia(file, activeAiMode.id, language);
      setAiResult(result);
    } catch (e) {
      showToast("AI Scan failed. Check connection.", "error");
    } finally {
      setIsScanning(false);
    }
  };

  const filteredListings = useMemo(() => {
    return listings.filter(l => 
      (activeCategory === 'All' || l.category === activeCategory) &&
      (l.name?.toLowerCase() || '').includes(searchQuery.toLowerCase())
    );
  }, [listings, activeCategory, searchQuery]);

  if (!role) {
    return (
      <div className="min-h-screen bg-[#fcfdfd] flex items-center justify-center p-6">
        <MotionDiv initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} className="max-w-md w-full space-y-12 text-center">
          <div className="space-y-4">
            <div className="w-24 h-24 bg-agri-forest rounded-[2.5rem] flex items-center justify-center text-5xl shadow-2xl mx-auto mb-6">🌾</div>
            <h1 className="text-5xl font-black text-agri-forest tracking-tighter">KrishiX</h1>
            <p className="text-agri-moss font-bold uppercase tracking-[0.2em] text-[10px]">Precision D2C Marketplace</p>
          </div>

          <div className="grid gap-4">
            <button onClick={() => setRole(UserRole.CONSUMER)} className="p-8 bg-white border-2 border-agri-sand rounded-[2.5rem] text-left hover:border-agri-leaf transition-all shadow-sm flex items-center gap-6 group active:scale-95">
              <div className="w-16 h-16 bg-agri-ivory rounded-2xl flex items-center justify-center text-3xl group-hover:rotate-12 transition-transform">🧺</div>
              <div><h3 className="font-black text-xl text-agri-forest">I want to Buy</h3><p className="text-sm text-agri-moss opacity-70">Direct from farmers.</p></div>
            </button>
            <button onClick={() => setRole(UserRole.FARMER)} className="p-8 bg-white border-2 border-agri-sand rounded-[2.5rem] text-left hover:border-agri-leaf transition-all shadow-sm flex items-center gap-6 group active:scale-95">
              <div className="w-16 h-16 bg-agri-ivory rounded-2xl flex items-center justify-center text-3xl group-hover:-rotate-12 transition-transform">🚜</div>
              <div><h3 className="font-black text-xl text-agri-forest">I want to Sell</h3><p className="text-sm text-agri-moss opacity-70">List products & use AI tools.</p></div>
            </button>
          </div>
        </MotionDiv>
      </div>
    );
  }

  return (
    <div className="min-h-screen pb-24 font-sans bg-slate-50">
      <AnimatePresence>
        {toast && (
          <MotionDiv initial={{ opacity: 0, y: -50 }} animate={{ opacity: 1, y: 0 }} exit={{ opacity: 0, y: -50 }} 
            className={`fixed top-6 left-1/2 -translate-x-1/2 z-[200] px-6 py-4 rounded-2xl shadow-2xl text-white font-bold flex items-center gap-3 ${toast.type === 'error' ? 'bg-red-600' : 'bg-agri-forest'}`}>
            {toast.type === 'error' ? <Info className="w-5 h-5" /> : <CheckCircle className="w-5 h-5" />}
            {toast.msg}
          </MotionDiv>
        )}
      </AnimatePresence>

      <header className="glass sticky top-0 z-50 p-4 border-b border-agri-sand/30">
        <div className="max-w-2xl mx-auto flex items-center justify-between">
          <div className="flex items-center gap-3 cursor-pointer" onClick={() => { setRole(null); setActiveTab('home'); }}>
            <div className="w-10 h-10 bg-agri-forest rounded-xl flex items-center justify-center text-xl shadow-lg">🌾</div>
            <h1 className="text-xl font-black text-agri-forest leading-none">KrishiX</h1>
          </div>
          <div className="flex items-center gap-2">
            {role === UserRole.CONSUMER && (
              <button onClick={() => setIsCartOpen(true)} className="relative p-3 bg-agri-sand/50 rounded-full hover:bg-agri-sand transition-all active:scale-90">
                <ShoppingCart className="w-6 h-6 text-agri-forest" />
                {cart.length > 0 && <span className="absolute -top-1 -right-1 bg-red-500 text-white text-[10px] w-5 h-5 flex items-center justify-center rounded-full border-2 border-white font-black">{cart.length}</span>}
              </button>
            )}
            <button onClick={() => setShowChat(true)} className="p-3 bg-agri-forest/5 rounded-full hover:bg-agri-forest/10"><Zap className="w-6 h-6 text-agri-forest" /></button>
          </div>
        </div>
      </header>

      <main className="max-w-2xl mx-auto p-4 py-6">
        {role === UserRole.CONSUMER && activeTab === 'home' && (
          <div className="space-y-6">
            <div className="bg-gradient-to-br from-agri-forest to-agri-moss rounded-[3rem] p-8 text-white relative overflow-hidden shadow-2xl">
              <div className="relative z-10 space-y-2">
                <p className="text-[10px] font-black uppercase tracking-[0.3em] opacity-60">Featured Farmers</p>
                <h2 className="text-3xl font-black leading-tight">Harvested Today,<br/>On your table tomorrow.</h2>
                <button className="mt-4 flex items-center gap-2 text-xs font-black bg-white/20 px-4 py-2 rounded-full backdrop-blur-md">Explore Now <ArrowRight className="w-4 h-4" /></button>
              </div>
              <ShoppingBag className="absolute -bottom-8 -right-8 w-48 h-48 opacity-10 rotate-12" />
            </div>

            <div className="relative group">
              <Search className="absolute left-5 top-1/2 -translate-y-1/2 text-agri-moss w-5 h-5 group-focus-within:text-agri-forest transition-colors" />
              <input type="text" placeholder="Search vegetables, fruits, dairy..." value={searchQuery} onChange={(e) => setSearchQuery(e.target.value)}
                className="w-full bg-white border-2 border-agri-sand rounded-3xl py-5 pl-14 pr-6 focus:ring-8 focus:ring-agri-forest/5 focus:border-agri-forest outline-none transition-all font-bold text-agri-forest shadow-sm" />
            </div>

            <div className="flex gap-3 overflow-x-auto no-scrollbar py-2">
              <button onClick={() => setActiveCategory('All')} className={`px-8 py-3 rounded-2xl font-black text-xs uppercase tracking-widest transition-all ${activeCategory === 'All' ? 'bg-agri-forest text-white shadow-xl' : 'bg-white text-agri-moss border border-agri-sand'}`}>All</button>
              {CATEGORIES.map(c => (
                <button key={c} onClick={() => setActiveCategory(c)} className={`px-8 py-3 rounded-2xl font-black text-xs uppercase tracking-widest transition-all ${activeCategory === c ? 'bg-agri-forest text-white shadow-xl' : 'bg-white text-agri-moss border border-agri-sand'}`}>{c}</button>
              ))}
            </div>

            <div className="grid grid-cols-2 gap-4 pb-12">
              {filteredListings.length === 0 ? (
                <div className="col-span-2 text-center py-20 opacity-30 italic font-bold">No results found for "{searchQuery}"</div>
              ) : (
                filteredListings.map(l => (
                  <MotionDiv layout key={l.id} className="bg-white rounded-[2.5rem] p-4 product-card-shadow border border-white flex flex-col group">
                    <div className="relative aspect-[4/5] rounded-[2rem] overflow-hidden mb-4 bg-agri-ivory">
                      <img src={l.image} className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-700" alt={l.name} />
                      {l.certified && (
                        <div className="absolute top-3 left-3 bg-agri-forest text-white text-[8px] font-black uppercase px-3 py-1.5 rounded-full shadow-2xl flex items-center gap-1 backdrop-blur-md">
                          <ShieldCheck className="w-3 h-3" /> AI Verified
                        </div>
